export type GridData = string[][];

export interface Dimensions {
  rows: number;
  cols: number;
}

export enum ToolType {
  PEN = 'PEN',
  ERASER = 'ERASER',
  FILL = 'FILL',
  EYEDROPPER = 'EYEDROPPER'
}

export const DEFAULT_COLOR = '#000000';
export const EMPTY_COLOR = 'transparent'; // Represents an erased/empty cell
export const PRESETS = [8, 12, 16, 24, 32];

// Converts RGB to Hex
export const rgbToHex = (r: number, g: number, b: number): string => {
  return "#" + ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1);
};

// Converts Hex to RGB
export const hexToRgb = (hex: string) => {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16)
  } : null;
};

import { GridData } from '../types';
import { rgbToHex } from './colorUtils';

/**
 * Processes an uploaded image file and converts it into a pixel grid.
 * It resizes the image to match the target grid dimensions.
 */
export const processImageToGrid = (
  file: File,
  rows: number,
  cols: number
): Promise<GridData> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');

        if (!ctx) {
          reject(new Error('Could not get canvas context'));
          return;
        }

        // Set canvas size to the grid dimensions
        canvas.width = cols;
        canvas.height = rows;

        // Draw and resize image
        ctx.drawImage(img, 0, 0, cols, rows);

        // Extract pixel data
        const imageData = ctx.getImageData(0, 0, cols, rows);
        const data = imageData.data;
        const newGrid: GridData = [];

        for (let y = 0; y < rows; y++) {
          const row: string[] = [];
          for (let x = 0; x < cols; x++) {
            const index = (y * cols + x) * 4;
            const r = data[index];
            const g = data[index + 1];
            const b = data[index + 2];
            const a = data[index + 3];

            // If fully transparent, use transparent string, else hex
            if (a < 50) {
              row.push('transparent');
            } else {
              row.push(rgbToHex(r, g, b));
            }
          }
          newGrid.push(row);
        }
        resolve(newGrid);
      };
      img.onerror = reject;
      img.src = event.target?.result as string;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Exports the current grid to a high-res PNG image.
 */
export const exportGridToImage = (grid: GridData, scale: number = 20) => {
  const rows = grid.length;
  const cols = grid[0].length;

  const canvas = document.createElement('canvas');
  canvas.width = cols * scale;
  canvas.height = rows * scale;

  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  grid.forEach((row, y) => {
    row.forEach((color, x) => {
      if (color !== 'transparent') {
        ctx.fillStyle = color;
        ctx.fillRect(x * scale, y * scale, scale, scale);
      }
    });
  });

  const link = document.createElement('a');
  link.download = `pixel-art-${Date.now()}.png`;
  link.href = canvas.toDataURL('image/png');
  link.click();
};

import { GoogleGenAI, Type } from "@google/genai";
import { GridData } from '../types';

export const generatePixelArtFromPrompt = async (
  prompt: string, 
  size: number
): Promise<GridData | null> => {
  try {
    if (!process.env.API_KEY) {
      console.warn("API Key is missing.");
      return null;
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // We ask for a flattened array of hex strings or a simple 2D structure.
    // However, the Schema definitions in the new SDK are strict.
    // Let's ask for an object containing the flat list of colors and dimensions to reconstruct,
    // or a 2D array structure directly if supported. Array of Arrays is supported.

    const modelId = "gemini-2.5-flash"; // Efficient for this task

    const response = await ai.models.generateContent({
      model: modelId,
      contents: `Generate a pixel art representation of: "${prompt}". 
      The grid size is ${size}x${size}. 
      Return a JSON object with a property 'grid' which is a 2D array (array of rows, where each row is an array of hex color strings). 
      Use valid 6-character hex codes (e.g., #FF0000). Use 'transparent' for empty space.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            grid: {
              type: Type.ARRAY,
              description: `A ${size}x${size} grid of colors.`,
              items: {
                type: Type.ARRAY,
                items: {
                    type: Type.STRING,
                    description: "Hex color code or 'transparent'"
                }
              }
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) return null;

    const data = JSON.parse(text);

    // Validate dimensions loosely
    if (data.grid && Array.isArray(data.grid)) {
      // Ensure it matches requested size (truncate or pad if AI messed up, though schema helps)
      const rawGrid: string[][] = data.grid;
      const cleanGrid: GridData = [];

      for(let i=0; i<size; i++) {
        const row: string[] = [];
        for(let j=0; j<size; j++) {
            const val = rawGrid[i]?.[j] || 'transparent';
            row.push(val);
        }
        cleanGrid.push(row);
      }
      return cleanGrid;
    }

    return null;
  } catch (error) {
    console.error("Error generating pixel art:", error);
    throw error;
  }
};

import React, { useRef, useEffect } from 'react';
import { GridData, ToolType, EMPTY_COLOR } from '../types';

interface GridProps {
  grid: GridData;
  setGrid: React.Dispatch<React.SetStateAction<GridData>>;
  activeColor: string;
  setActiveColor: (c: string) => void;
  tool: ToolType;
  showGridLines: boolean;
}

const Grid: React.FC<GridProps> = ({ 
  grid, 
  setGrid, 
  activeColor, 
  setActiveColor,
  tool, 
  showGridLines 
}) => {
  const isDrawing = useRef(false);

  // Helper to paint a specific cell
  const paintCell = (rowIndex: number, colIndex: number) => {
    if (rowIndex < 0 || rowIndex >= grid.length || colIndex < 0 || colIndex >= grid[0].length) return;

    // Optimization: Don't update state if color is identical
    const currentColor = grid[rowIndex][colIndex];
    let targetColor = activeColor;

    if (tool === ToolType.ERASER) {
      targetColor = EMPTY_COLOR;
    } else if (tool === ToolType.EYEDROPPER) {
        if (currentColor !== EMPTY_COLOR) {
            setActiveColor(currentColor);
        }
        return; // Don't paint
    }

    if (currentColor === targetColor) return;

    setGrid(prev => {
      const newGrid = [...prev]; // Shallow copy outer
      newGrid[rowIndex] = [...prev[rowIndex]]; // Copy row
      newGrid[rowIndex][colIndex] = targetColor;
      return newGrid;
    });
  };

  const handleMouseDown = (r: number, c: number) => {
    isDrawing.current = true;
    paintCell(r, c);
  };

  const handleMouseEnter = (r: number, c: number) => {
    if (isDrawing.current) {
      paintCell(r, c);
    }
  };

  const handleMouseUp = () => {
    isDrawing.current = false;
  };

  // Global mouse up to catch drags that go outside
  useEffect(() => {
    const handleGlobalMouseUp = () => { isDrawing.current = false; };
    window.addEventListener('mouseup', handleGlobalMouseUp);
    return () => window.removeEventListener('mouseup', handleGlobalMouseUp);
  }, []);

  // Determine grid cell size based on viewport (simple logic)
  // For a more robust solution, we use flex/grid CSS.

  return (
    <div 
      className="select-none inline-block shadow-2xl bg-slate-800 p-1 rounded-sm border border-slate-700"
      onMouseLeave={handleMouseUp}
      style={{
        display: 'grid',
        gridTemplateColumns: `repeat(${grid[0].length}, 1fr)`,
        gap: '0px', 
        // Force a max size to keep it within view
        maxWidth: '100%',
        maxHeight: '80vh',
        aspectRatio: '1 / 1',
        width: 'min(600px, 90vw)', 
      }}
    >
      {grid.map((row, rIndex) => (
        row.map((color, cIndex) => (
          <div
            key={`${rIndex}-${cIndex}`}
            onMouseDown={() => handleMouseDown(rIndex, cIndex)}
            onMouseEnter={() => handleMouseEnter(rIndex, cIndex)}
            style={{ 
                backgroundColor: color === 'transparent' ? undefined : color,
                backgroundImage: color === 'transparent' 
                  ? 'linear-gradient(45deg, #1e293b 25%, transparent 25%), linear-gradient(-45deg, #1e293b 25%, transparent 25%), linear-gradient(45deg, transparent 75%, #1e293b 75%), linear-gradient(-45deg, transparent 75%, #1e293b 75%)' 
                  : 'none',
                backgroundSize: '10px 10px',
                backgroundPosition: '0 0, 0 5px, 5px -5px, -5px 0px'
            }}
            className={`
              w-full h-full cursor-crosshair
              ${showGridLines ? 'border-[0.5px] border-slate-700/50' : ''}
              hover:opacity-90 transition-opacity duration-75
            `}
          />
        ))
      ))}
    </div>
  );
};

export default Grid;

import React, { useRef } from 'react';
