            >
              {size}
            </button>
          ))}
        </div>
      </div>

      {/* --- Tools --- */}
      <div>
        <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2 block">Tools</label>
        <div className="grid grid-cols-4 gap-2">
          <ToolButton 
            active={tool === ToolType.PEN} 
            onClick={() => setTool(ToolType.PEN)} 
