);

const ActionButton = ({ onClick, icon, label, variant = 'primary' }: any) => {
  const styles = {
    primary: 'bg-slate-700 hover:bg-slate-600 text-white border-slate-600',
    secondary: 'bg-slate-700/50 hover:bg-slate-700 text-slate-300 border-dashed border-slate-500',
    danger: 'bg-red-500/10 hover:bg-red-500/20 text-red-400 border-red-500/30',
    ai: 'bg-gradient-to-r from-purple-600 to-pink-600 hover:from-purple-500 hover:to-pink-500 text-white border-transparent shadow-lg shadow-purple-500/20'
