};

export default Toolbar;

import React, { useState } from 'react';
import { X, Wand2 } from 'lucide-react';

interface AIPromptModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (prompt: string) => void;
  isGenerating: boolean;
}

const AIPromptModal: React.FC<AIPromptModalProps> = ({ isOpen, onClose, onSubmit, isGenerating }) => {
  const [prompt, setPrompt] = useState('');

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (prompt.trim()) {
      onSubmit(prompt);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
      <div className="bg-slate-800 border border-slate-700 rounded-2xl w-full max-w-md shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="flex justify-between items-center p-4 border-b border-slate-700 bg-slate-800/50">
          <h3 className="text-lg font-semibold text-white flex items-center gap-2">
            <Wand2 className="text-purple-400" size={20} />
            AI Pixel Generator
          </h3>
          <button 
            onClick={onClose}
            className="text-slate-400 hover:text-white transition-colors"
          >
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6">
          <p className="text-sm text-slate-300 mb-4">
            Describe what you want to create, and Gemini will convert it into pixel art for your current grid size.
          </p>

          <textarea
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            placeholder="e.g., A red mushroom with white spots, 8-bit style"
            className="w-full h-32 bg-slate-900 border border-slate-700 rounded-xl p-3 text-white placeholder:text-slate-500 focus:outline-none focus:ring-2 focus:ring-purple-500/50 resize-none mb-4"
            autoFocus
          />

          <div className="flex justify-end gap-3">
             <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 text-sm text-slate-300 hover:text-white hover:bg-slate-700 rounded-lg transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={!prompt.trim() || isGenerating}
              className="px-6 py-2 bg-purple-600 hover:bg-purple-500 text-white rounded-lg text-sm font-medium transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
            >
              {isGenerating ? 'Generating...' : 'Generate Art'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AIPromptModal;

import React, { useState, useEffect, useCallback } from 'react';
import Grid from './components/Grid';
import Toolbar from './components/Toolbar';
import AIPromptModal from './components/AIPromptModal';
import { GridData, ToolType, DEFAULT_COLOR, EMPTY_COLOR } from './types';
import { processImageToGrid, exportGridToImage } from './utils/imageHelper';
import { generatePixelArtFromPrompt } from './services/geminiService';

const App: React.FC = () => {
  // State
  const [gridSize, setGridSize] = useState<number>(16);
  const [grid, setGrid] = useState<GridData>([]);
  const [activeColor, setActiveColor] = useState<string>(DEFAULT_COLOR);
  const [tool, setTool] = useState<ToolType>(ToolType.PEN);
  const [showGridLines, setShowGridLines] = useState<boolean>(true);

  // AI Modal State
  const [isAIModalOpen, setIsAIModalOpen] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);

  // Initialize Grid
  useEffect(() => {
    // Only reset if dimensions actually changed to avoid clearing user work unnecessarily
    // But since we want resizing to clear (simplification), we rebuild.
    const newGrid = Array(gridSize).fill(null).map(() => Array(gridSize).fill(EMPTY_COLOR));
    setGrid(newGrid);
  }, [gridSize]);

  // Handlers
  const handleClear = () => {
    if (window.confirm('Clear the entire board?')) {
      setGrid(prev => prev.map(row => row.map(() => EMPTY_COLOR)));
    }
  };

  const handleDownload = () => {
    exportGridToImage(grid);
  };

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const newGrid = await processImageToGrid(file, gridSize, gridSize);
      setGrid(newGrid);
      // Reset file input
      e.target.value = '';
    } catch (error) {
      console.error("Failed to process image", error);
      alert("Error processing image. Please try a different file.");
    }
  };

  const handleGenerateAI = useCallback(async (prompt: string) => {
    setIsGenerating(true);
    try {
      const generatedGrid = await generatePixelArtFromPrompt(prompt, gridSize);
      if (generatedGrid) {
        setGrid(generatedGrid);
        setIsAIModalOpen(false);
      } else {
        alert("Could not generate art. Please try a different prompt or check API key.");
      }
    } catch (err) {
      console.error(err);
      alert("AI Generation failed. See console.");
    } finally {
      setIsGenerating(false);
    }
  }, [gridSize]);

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 flex flex-col items-center justify-center p-4 md:p-8 relative overflow-hidden">

      {/* Background decoration */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0">
         <div className="absolute top-[-20%] left-[-10%] w-[50%] h-[50%] bg-blue-600/10 rounded-full blur-[120px]"></div>
         <div className="absolute bottom-[-20%] right-[-10%] w-[50%] h-[50%] bg-purple-600/10 rounded-full blur-[120px]"></div>
      </div>

      <header className="mb-8 z-10 text-center">
        <h1 className="text-4xl md:text-5xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-purple-400 mb-2">
          Pixel Art Studio
        </h1>
        <p className="text-slate-400">Draw, Upload, or Dream with AI</p>
      </header>

      <main className="w-full max-w-6xl z-10 flex flex-col md:flex-row gap-8 items-start justify-center">

        {/* Left Control Panel (Mobile: Top) */}
        <section className="w-full md:w-auto order-2 md:order-1 flex justify-center">
          <Toolbar 
            tool={tool}
            setTool={setTool}
            activeColor={activeColor}
            setActiveColor={setActiveColor}
            gridSize={gridSize}
            setGridSize={setGridSize}
            onClear={handleClear}
            onDownload={handleDownload}
            onUpload={handleUpload}
            showGridLines={showGridLines}
            setShowGridLines={setShowGridLines}
            isGenerating={isGenerating}
            onGenerateAI={() => setIsAIModalOpen(true)}
          />
        </section>

        {/* Center Canvas */}
        <section className="flex-1 flex items-center justify-center order-1 md:order-2 bg-slate-800/30 p-4 md:p-8 rounded-3xl border border-slate-700/50 shadow-2xl backdrop-blur-sm">
           <Grid 
             grid={grid}
             setGrid={setGrid}
             activeColor={activeColor}
             setActiveColor={setActiveColor}
             tool={tool}
             showGridLines={showGridLines}
           />
        </section>

      </main>

      <footer className="mt-12 text-slate-600 text-sm z-10">
        <p>Built with Gemini 2.5 Flash, React & Tailwind</p>
      </footer>

      {/* AI Modal */}
      <AIPromptModal 
        isOpen={isAIModalOpen} 
        onClose={() => setIsAIModalOpen(false)}
        onSubmit={handleGenerateAI}
