            {PRESETS.map(size => (
              <button
                key={size}
                onClick={() => setGridSize(size)}
                className={`
                  flex-1 px-3 py-1.5 text-sm font-medium rounded-md border transition-all
                  ${gridSize === size 
                    ? 'bg-blue-600 border-blue-500 text-white shadow-lg shadow-blue-500/20' 
                    : 'bg-slate-700 border-slate-600 text-slate-300 hover:bg-slate-600'}
                `}
              >
                {size}
              </button>
            ))}
          </div>

          {/* Custom Input */}
          <div className="flex items-center gap-2 bg-slate-900/50 p-2 rounded-lg border border-slate-700/50">
             <span className="text-xs text-slate-400 font-medium whitespace-nowrap px-1">Custom:</span>
             <input 
                type="number"
                min={4}
                max={40}
                value={customSize}
                onChange={(e) => setCustomSize(e.target.value)}
                onBlur={handleCustomSizeCommit}
                onKeyDown={handleKeyDown}
                className="w-full bg-transparent text-sm text-right text-white focus:outline-none placeholder-slate-600"
                placeholder="4-40"
             />
             <span className="text-xs text-slate-500 pr-1">px</span>
          </div>
        </div>
      </div>

      {/* --- Board Style --- */}
      <div>
        <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2 block">Board Style</label>
        <div className="grid grid-cols-2 gap-2">
           <ToolButton 
             active={boardStyle === BoardStyle.SQUARE}
             onClick={() => setBoardStyle(BoardStyle.SQUARE)}
             icon={<Square size={18} />}
             label="Square"
           />
           <ToolButton 
             active={boardStyle === BoardStyle.BEAD}
             onClick={() => setBoardStyle(BoardStyle.BEAD)}
             icon={<Circle size={18} />}
             label="Bead"
           />
        </div>

        {/* Bead Size Slider - Only visible in Bead mode */}
        {boardStyle === BoardStyle.BEAD && (
            <div className="mt-3 bg-slate-900/30 p-2 rounded-lg border border-slate-700/30 animate-in fade-in slide-in-from-top-2 duration-200">
                <div className="flex justify-between items-center mb-1">
                    <span className="text-[10px] uppercase font-bold text-slate-500">Bead Diameter</span>
                    <span className="text-xs text-slate-300 font-mono">{beadSize}%</span>
                </div>
                <input 
                    type="range" 
                    min="20" 
                    max="100" 
                    step="5"
                    value={beadSize}
                    onChange={(e) => setBeadSize(Number(e.target.value))}
                    className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500 hover:accent-blue-400"
                />
            </div>
        )}
      </div>

      {/* --- Tools --- */}
      <div>
        <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2 block">Tools</label>
        <div className="grid grid-cols-4 gap-2">
          <ToolButton 
            active={tool === ToolType.PEN} 
            onClick={() => setTool(ToolType.PEN)} 
            icon={<Pencil size={18} />} 
            label="Pen"
          />
          <ToolButton 
            active={tool === ToolType.ERASER} 
            onClick={() => setTool(ToolType.ERASER)} 
            icon={<Eraser size={18} />} 
