            icon={<Grid3X3 size={18} />} 
            label="Grid"
          />
        </div>
      </div>

      {/* --- Colors --- */}
      <div>
        <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2 block">Palette</label>
        <div className="grid grid-cols-6 gap-2 mb-3">
          {colors.map(c => (
            <button
              key={c}
              onClick={() => setActiveColor(c)}
              className={`
                w-8 h-8 rounded-full border-2 transition-transform hover:scale-110
                ${activeColor === c ? 'border-white ring-2 ring-blue-500' : 'border-transparent'}
              `}
              style={{ backgroundColor: c }}
            />
          ))}
        </div>
        <div className="flex items-center gap-2 bg-slate-700/50 p-2 rounded-lg">
          <input 
            type="color" 
            value={activeColor}
            onChange={(e) => setActiveColor(e.target.value)}
            className="w-8 h-8 rounded cursor-pointer bg-transparent border-none p-0"
          />
          <span className="text-xs text-slate-300 font-mono uppercase">{activeColor}</span>
        </div>
      </div>

      {/* --- Recent Colors --- */}
      {recentColors.length > 0 && (
          <div className="pt-2 border-t border-slate-700/50">
            <button 
                onClick={() => setShowRecent(!showRecent)}
                className="flex items-center justify-between w-full text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2 hover:text-slate-300 transition-colors"
            >
                <span className="flex items-center gap-1.5">
                    <Clock size={12} />
                    Recent
