import React, { useRef, useState, useEffect } from 'react';
import { 
  Pencil, 
  Eraser, 
  Pipette, 
  Trash2, 
  Download, 
  Grid3X3, 
  Image as ImageIcon,
  Square,
  Circle,
  Clock,
  ChevronDown,
  ChevronUp
} from 'lucide-react';
import { ToolType, PRESETS, BoardStyle } from '../types';

interface ToolbarProps {
  tool: ToolType;
  setTool: (t: ToolType) => void;
  activeColor: string;
  setActiveColor: (c: string) => void;
  gridSize: number;
  setGridSize: (s: number) => void;
  onClear: () => void;
  onDownload: () => void;
  onUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
  showGridLines: boolean;
  setShowGridLines: (v: boolean) => void;
  boardStyle: BoardStyle;
  setBoardStyle: (s: BoardStyle) => void;
  beadSize: number;
  setBeadSize: (s: number) => void;
}

const Toolbar: React.FC<ToolbarProps> = ({
  tool, setTool,
  activeColor, setActiveColor,
  gridSize, setGridSize,
  onClear,
  onDownload,
  onUpload,
  showGridLines, setShowGridLines,
  boardStyle, setBoardStyle,
  beadSize, setBeadSize
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Local state for the custom input to allow typing
  const [customSize, setCustomSize] = useState<string>(gridSize.toString());

  // Recent Colors State
  const [recentColors, setRecentColors] = useState<string[]>([]);
  const [showRecent, setShowRecent] = useState<boolean>(true);

  // Sync local input when external grid size changes
  useEffect(() => {
    setCustomSize(gridSize.toString());
  }, [gridSize]);

  // Track active color usage for history
  useEffect(() => {
    if (!activeColor || activeColor === 'transparent') return;

    const handler = setTimeout(() => {
      setRecentColors(prev => {
        // If the color is already the most recent, do nothing
        if (prev[0] === activeColor) return prev;
        // Otherwise, move it to front or add it
        const filtered = prev.filter(c => c !== activeColor);
        return [activeColor, ...filtered].slice(0, 12); // Limit to 12 colors
      });
    }, 500); // Debounce to capture final color after picking

    return () => clearTimeout(handler);
  }, [activeColor]);

  const handleCustomSizeCommit = () => {
    let val = parseInt(customSize, 10);

    if (isNaN(val)) {
      setCustomSize(gridSize.toString());
      return;
    }

    // Enforce limits 4 - 40
    if (val < 4) val = 4;
    if (val > 40) val = 40;

    setCustomSize(val.toString());
    if (val !== gridSize) {
      setGridSize(val);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleCustomSizeCommit();
      (e.target as HTMLInputElement).blur();
    }
  };

  const colors = [
    '#000000', '#1a1c2c', '#5d275d', '#b13e53', '#ef7d57',
    '#ffcd75', '#a7f070', '#38b764', '#257179', '#29366f',
    '#3b5dc9', '#41a6f6', '#73eff7', '#f4f4f4', '#94b0c2',
    '#566c86', '#333c57'
  ];

  const handleFileClick = () => {
    fileInputRef.current?.click();
  };

  return (
    <div className="flex flex-col gap-6 p-5 bg-slate-800/50 backdrop-blur-xl border border-slate-700 rounded-2xl shadow-xl w-full max-w-xs h-fit overflow-y-auto max-h-[90vh]">

      {/* --- Size Selector --- */}
      <div>
        <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2 block">
          Canvas Size
        </label>
        <div className="flex flex-col gap-3">
          <div className="flex flex-wrap gap-2">
            {PRESETS.map(size => (
              <button
                key={size}
                type="button"
                onClick={() => setGridSize(size)}
                className={`
                  flex-1 px-3 py-1.5 text-sm font-medium rounded-md border transition-all
                  ${gridSize === size 
                    ? 'bg-blue-600 border-blue-500 text-white shadow-lg shadow-blue-500/20' 
                    : 'bg-slate-700 border-slate-600 text-slate-300 hover:bg-slate-600'}
                `}
              >
                {size}
              </button>
            ))}
          </div>

          {/* Custom Input */}
          <div className="flex items-center gap-2 bg-slate-900/50 p-2 rounded-lg border border-slate-700/50">
             <span className="text-xs text-slate-400 font-medium whitespace-nowrap px-1">Custom:</span>
             <input 
                type="number"
                min={4}
                max={40}
                value={customSize}
                onChange={(e) => setCustomSize(e.target.value)}
                onBlur={handleCustomSizeCommit}
                onKeyDown={handleKeyDown}
                className="w-full bg-transparent text-sm text-right text-white focus:outline-none placeholder-slate-600"
                placeholder="4-40"
             />
             <span className="text-xs text-slate-500 pr-1">px</span>
          </div>
        </div>
      </div>

      {/* --- Board Style --- */}
      <div>
        <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2 block">Board Style</label>
        <div className="grid grid-cols-2 gap-2">
           <ToolButton 
             active={boardStyle === BoardStyle.SQUARE}
             onClick={() => setBoardStyle(BoardStyle.SQUARE)}
             icon={<Square size={18} />}
             label="Square"
           />
           <ToolButton 
             active={boardStyle === BoardStyle.BEAD}
             onClick={() => setBoardStyle(BoardStyle.BEAD)}
             icon={<Circle size={18} />}
             label="Bead"
           />
        </div>

        {/* Bead Size Slider - Only visible in Bead mode */}
        {boardStyle === BoardStyle.BEAD && (
            <div className="mt-3 bg-slate-900/30 p-2 rounded-lg border border-slate-700/30 animate-in fade-in slide-in-from-top-2 duration-200">
                <div className="flex justify-between items-center mb-1">
                    <span className="text-[10px] uppercase font-bold text-slate-500">Bead Diameter</span>
                    <span className="text-xs text-slate-300 font-mono">{beadSize}%</span>
                </div>
                <input 
                    type="range" 
                    min="20" 
                    max="100" 
                    step="5"
                    value={beadSize}
                    onChange={(e) => setBeadSize(Number(e.target.value))}
                    className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500 hover:accent-blue-400"
                />
            </div>
        )}
      </div>

      {/* --- Tools --- */}
      <div>
        <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2 block">Tools</label>
        <div className="grid grid-cols-4 gap-2">
          <ToolButton 
            active={tool === ToolType.PEN} 
            onClick={() => setTool(ToolType.PEN)} 
            icon={<Pencil size={18} />} 
            label="Pen"
          />
          <ToolButton 
            active={tool === ToolType.ERASER} 
            onClick={() => setTool(ToolType.ERASER)} 
            icon={<Eraser size={18} />} 
            label="Erase"
          />
          <ToolButton 
            active={tool === ToolType.EYEDROPPER} 
            onClick={() => setTool(ToolType.EYEDROPPER)} 
            icon={<Pipette size={18} />} 
            label="Pick"
          />
          <ToolButton 
            active={showGridLines} 
            onClick={() => setShowGridLines(!showGridLines)} 
            icon={<Grid3X3 size={18} />} 
            label="Grid"
          />
        </div>
      </div>

      {/* --- Colors --- */}
      <div>
        <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2 block">Palette</label>
        <div className="grid grid-cols-6 gap-2 mb-3">
          {colors.map(c => (
            <button
              key={c}
              type="button"
              onClick={() => setActiveColor(c)}
              className={`
                w-8 h-8 rounded-full border-2 transition-transform hover:scale-110
                ${activeColor === c ? 'border-white ring-2 ring-blue-500' : 'border-transparent'}
              `}
              style={{ backgroundColor: c }}
            />
          ))}
        </div>
        <div className="flex items-center gap-2 bg-slate-700/50 p-2 rounded-lg">
          <input 
            type="color" 
            value={activeColor}
            onChange={(e) => setActiveColor(e.target.value)}
            className="w-8 h-8 rounded cursor-pointer bg-transparent border-none p-0"
          />
          <span className="text-xs text-slate-300 font-mono uppercase">{activeColor}</span>
        </div>
      </div>

      {/* --- Recent Colors --- */}
      {recentColors.length > 0 && (
          <div className="pt-2 border-t border-slate-700/50">
            <button 
                type="button"
                onClick={() => setShowRecent(!showRecent)}
                className="flex items-center justify-between w-full text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2 hover:text-slate-300 transition-colors"
            >
                <span className="flex items-center gap-1.5">
                    <Clock size={12} />
                    Recent
                </span>
                {showRecent ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
            </button>

            {showRecent && (
                <div className="grid grid-cols-6 gap-2 mb-3 animate-in fade-in slide-in-from-top-1 duration-200">
                {recentColors.map(c => (
                    <button
                    key={c}
                    type="button"
                    onClick={() => setActiveColor(c)}
                    className={`
                        w-8 h-8 rounded-full border-2 transition-transform hover:scale-110 shadow-sm
                        ${activeColor === c ? 'border-white ring-2 ring-blue-500/50' : 'border-slate-600/50'}
                    `}
                    style={{ backgroundColor: c }}
                    title={c}
                    />
                ))}
                </div>
            )}
          </div>
      )}

      {/* --- Actions --- */}
      <div className="space-y-3 pt-4 border-t border-slate-700">

        <input 
          type="file" 
          ref={fileInputRef}
          onChange={onUpload}
          accept="image/*"
          className="hidden" 
        />

        <ActionButton 
          onClick={handleFileClick} 
          icon={<ImageIcon size={18} />} 
          label="Upload Image to Grid" 
          variant="secondary"
        />

        <div className="grid grid-cols-2 gap-2">
            <ActionButton 
                onClick={onClear} 
                icon={<Trash2 size={18} />} 
                label="Clear" 
                variant="danger"
            />
            <ActionButton 
                onClick={onDownload} 
                icon={<Download size={18} />} 
                label="Save" 
                variant="primary"
            />
        </div>
      </div>
    </div>
  );
};

