import { translations } from '../utils/translations';

interface ToolbarProps {
  tool: ToolType;
  setTool: (t: ToolType) => void;
  activeColor: string;
  setActiveColor: (c: string) => void;
  gridSize: number;
  setGridSize: (s: number) => void;
  onClear: () => void;
  onDownload: () => void;
  onUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
  showGridLines: boolean;
  setShowGridLines: (v: boolean) => void;
  boardStyle: BoardStyle;
  setBoardStyle: (s: BoardStyle) => void;
  beadSize: number;
  setBeadSize: (s: number) => void;
  lang: Language;
  theme: Theme;
}

const Toolbar: React.FC<ToolbarProps> = ({
  tool, setTool,
  activeColor, setActiveColor,
  gridSize, setGridSize,
  onClear,
  onDownload,
  onUpload,
  showGridLines, setShowGridLines,
  boardStyle, setBoardStyle,
  beadSize, setBeadSize,
  lang,
  theme
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isDark = theme === 'dark';

  // Local state for the custom input to allow typing
  const [customSize, setCustomSize] = useState<string>(gridSize.toString());

  // Recent Colors State
  const [recentColors, setRecentColors] = useState<string[]>([]);
  const [showRecent, setShowRecent] = useState<boolean>(true);

  const t = translations[lang];

  // Sync local input when external grid size changes
  useEffect(() => {
    setCustomSize(gridSize.toString());
  }, [gridSize]);

  // Track active color usage for history
  useEffect(() => {
    if (!activeColor || activeColor === 'transparent') return;

    const handler = setTimeout(() => {
      setRecentColors(prev => {
        // If the color is already the most recent, do nothing
        if (prev[0] === activeColor) return prev;
        // Otherwise, move it to front or add it
        const filtered = prev.filter(c => c !== activeColor);
        return [activeColor, ...filtered].slice(0, 12); // Limit to 12 colors
      });
    }, 500); // Debounce to capture final color after picking

    return () => clearTimeout(handler);
  }, [activeColor]);

  const handleCustomSizeCommit = () => {
    let val = parseInt(customSize, 10);

    if (isNaN(val)) {
      setCustomSize(gridSize.toString());
      return;
    }

    // Enforce limits 4 - 40
    if (val < 4) val = 4;
    if (val > 40) val = 40;

    setCustomSize(val.toString());
    if (val !== gridSize) {
      setGridSize(val);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleCustomSizeCommit();
      (e.target as HTMLInputElement).blur();
    }
  };

  const colors = [
    '#000000', '#1a1c2c', '#5d275d', '#b13e53', '#ef7d57',
    '#ffcd75', '#a7f070', '#38b764', '#257179', '#29366f',
    '#3b5dc9', '#41a6f6', '#73eff7', '#f4f4f4', '#94b0c2',
    '#566c86', '#333c57'
  ];

  const handleFileClick = () => {
    fileInputRef.current?.click();
  };

  // Styles based on theme
  const containerClass = isDark 
    ? 'bg-slate-800/50 border-slate-700 text-slate-100' 
    : 'bg-white/80 border-slate-200 text-slate-800 shadow-slate-200';

  const labelClass = isDark ? 'text-slate-400' : 'text-slate-500';

  const inputContainerClass = isDark 
    ? 'bg-slate-900/50 border-slate-700/50' 
    : 'bg-slate-100 border-slate-200';

  const inputTextClass = isDark ? 'text-white' : 'text-slate-800';

  const btnBaseClass = isDark 
    ? 'bg-slate-700 text-slate-400 border-slate-600 hover:bg-slate-600 hover:text-slate-200' 
    : 'bg-slate-100 text-slate-500 border-slate-200 hover:bg-slate-200 hover:text-slate-800';

  const btnActiveClass = isDark 
    ? 'bg-blue-600 border-blue-500 text-white shadow-lg shadow-blue-500/20' 
    : 'bg-blue-500 border-blue-400 text-white shadow-lg shadow-blue-500/20';

  return (
    <div className={`flex flex-col gap-6 p-5 backdrop-blur-xl border rounded-2xl shadow-xl w-full max-w-xs h-fit overflow-y-auto max-h-[90vh] transition-colors duration-300 ${containerClass}`}>

      {/* --- Size Selector --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>
          {t.size_label}
        </label>
        <div className="flex flex-col gap-3">
          <div className="flex flex-wrap gap-2">
            {PRESETS.map(size => (
              <button
                key={size}
                type="button"
                onClick={() => setGridSize(size)}
                className={`
                  flex-1 px-3 py-1.5 text-sm font-medium rounded-md border transition-all
                  ${gridSize === size ? btnActiveClass : btnBaseClass}
                `}
              >
                {size}
              </button>
            ))}
          </div>

          {/* Custom Input */}
          <div className={`flex items-center gap-2 p-2 rounded-lg border ${inputContainerClass}`}>
             <span className={`text-xs font-medium whitespace-nowrap px-1 ${labelClass}`}>{t.custom_size}:</span>
             <input 
                type="number"
                min={4}
                max={40}
                value={customSize}
                onChange={(e) => setCustomSize(e.target.value)}
                onBlur={handleCustomSizeCommit}
                onKeyDown={handleKeyDown}
                className={`w-full bg-transparent text-sm text-right focus:outline-none placeholder-slate-400 ${inputTextClass}`}
                placeholder="4-40"
             />
             <span className="text-xs text-slate-400 pr-1">px</span>
          </div>
        </div>
      </div>

      {/* --- Board Style --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>{t.board_style}</label>
        <div className="grid grid-cols-2 gap-2">
           <ToolButton 
             active={boardStyle === BoardStyle.SQUARE}
             onClick={() => setBoardStyle(BoardStyle.SQUARE)}
             icon={<Square size={18} />}
             label={t.style_square}
             theme={theme}
           />
           <ToolButton 
             active={boardStyle === BoardStyle.BEAD}
             onClick={() => setBoardStyle(BoardStyle.BEAD)}
             icon={<Circle size={18} />}
             label={t.style_bead}
             theme={theme}
           />
        </div>

        {/* Bead Size Slider - Only visible in Bead mode */}
        {boardStyle === BoardStyle.BEAD && (
            <div className={`mt-3 p-2 rounded-lg border animate-in fade-in slide-in-from-top-2 duration-200 ${isDark ? 'bg-slate-900/30 border-slate-700/30' : 'bg-slate-50 border-slate-200'}`}>
                <div className="flex justify-between items-center mb-1">
                    <span className="text-[10px] uppercase font-bold text-slate-500">{t.bead_diameter}</span>
                    <span className={`text-xs font-mono ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>{beadSize}%</span>
                </div>
                <input 
                    type="range" 
                    min="20" 
                    max="100" 
                    step="5"
                    value={beadSize}
                    onChange={(e) => setBeadSize(Number(e.target.value))}
                    className={`w-full h-1.5 rounded-lg appearance-none cursor-pointer accent-blue-500 hover:accent-blue-400 ${isDark ? 'bg-slate-700' : 'bg-slate-300'}`}
                />
            </div>
        )}
      </div>

      {/* --- Tools --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>{t.tools_label}</label>
        <div className="grid grid-cols-4 gap-2">
          <ToolButton 
            active={tool === ToolType.PEN} 
            onClick={() => setTool(ToolType.PEN)} 
            icon={<Pencil size={18} />} 
            label={t.tool_pen}
            theme={theme}
          />
          <ToolButton 
            active={tool === ToolType.ERASER} 
            onClick={() => setTool(ToolType.ERASER)} 
            icon={<Eraser size={18} />} 
            label={t.tool_eraser}
            theme={theme}
          />
          <ToolButton 
            active={tool === ToolType.EYEDROPPER} 
            onClick={() => setTool(ToolType.EYEDROPPER)} 
            icon={<Pipette size={18} />} 
            label={t.tool_pick}
            theme={theme}
          />
          <ToolButton 
            active={showGridLines} 
            onClick={() => setShowGridLines(!showGridLines)} 
            icon={<Grid3X3 size={18} />} 
            label={t.tool_grid}
            theme={theme}
          />
        </div>
      </div>

      {/* --- Colors --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>{t.palette_label}</label>
        <div className="grid grid-cols-6 gap-2 mb-3">
          {colors.map(c => (
            <button
              key={c}
              type="button"
              onClick={() => setActiveColor(c)}
              className={`
                w-8 h-8 rounded-full border-2 transition-transform hover:scale-110
                ${activeColor === c ? 'border-white ring-2 ring-blue-500' : 'border-transparent'}
              `}
              style={{ backgroundColor: c }}
            />
          ))}
        </div>
        <div className={`flex items-center gap-2 p-2 rounded-lg ${isDark ? 'bg-slate-700/50' : 'bg-slate-200/50'}`}>
          <input 
            type="color" 
            value={activeColor}
            onChange={(e) => setActiveColor(e.target.value)}
            className="w-8 h-8 rounded cursor-pointer bg-transparent border-none p-0"
          />
          <span className={`text-xs font-mono uppercase ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>{activeColor}</span>
        </div>
      </div>

      {/* --- Recent Colors --- */}
      {recentColors.length > 0 && (
          <div className={`pt-2 border-t ${isDark ? 'border-slate-700/50' : 'border-slate-200'}`}>
            <button 
                type="button"
                onClick={() => setShowRecent(!showRecent)}
                className={`flex items-center justify-between w-full text-xs font-semibold uppercase tracking-wider mb-2 transition-colors ${isDark ? 'text-slate-400 hover:text-slate-300' : 'text-slate-500 hover:text-slate-700'}`}
            >
                <span className="flex items-center gap-1.5">
                    <Clock size={12} />
                    {t.recent_label}
                </span>
                {showRecent ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
            </button>

            {showRecent && (
                <div className="grid grid-cols-6 gap-2 mb-3 animate-in fade-in slide-in-from-top-1 duration-200">
                {recentColors.map(c => (
                    <button
                    key={c}
                    type="button"
                    onClick={() => setActiveColor(c)}
                    className={`
                        w-8 h-8 rounded-full border-2 transition-transform hover:scale-110 shadow-sm
                        ${activeColor === c ? 'border-white ring-2 ring-blue-500/50' : (isDark ? 'border-slate-600/50' : 'border-slate-300')}
                    `}
                    style={{ backgroundColor: c }}
                    title={c}
                    />
                ))}
                </div>
            )}
          </div>
      )}

      {/* --- Actions --- */}
      <div className={`space-y-3 pt-4 border-t ${isDark ? 'border-slate-700' : 'border-slate-200'}`}>

        <input 
          type="file" 
          ref={fileInputRef}
          onChange={onUpload}
          accept="image/*"
          className="hidden" 
        />

        <ActionButton 
          onClick={handleFileClick} 
          icon={<ImageIcon size={18} />} 
          label={t.upload_image} 
          variant="secondary"
          theme={theme}
        />

        <div className="grid grid-cols-2 gap-2">
            <ActionButton 
                onClick={onClear} 
                icon={<Trash2 size={18} />} 
                label={t.clear} 
                variant="danger"
                theme={theme}
            />
            <ActionButton 
                onClick={onDownload} 
                icon={<Download size={18} />} 
                label={t.save_image} 
                variant="primary"
                theme={theme}
            />
        </div>
      </div>
    </div>
  );
};

// --- Sub-components for styling ---

const ToolButton = ({ active, onClick, icon, label, theme }: any) => {
  const isDark = theme === 'dark';
  return (
    <button
      type="button"
      onClick={onClick}
      title={label}
      className={`
        flex items-center justify-center gap-2 p-3 rounded-xl transition-all
        ${active 
          ? (isDark ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/25' : 'bg-blue-500 text-white shadow-lg shadow-blue-500/25')
          : (isDark ? 'bg-slate-700 text-slate-400 hover:bg-slate-600 hover:text-slate-200' : 'bg-slate-100 text-slate-500 hover:bg-slate-200 hover:text-slate-800')}
      `}
    >
      {icon}
    </button>
  );
};

const ActionButton = ({ onClick, icon, label, variant = 'primary', theme }: any) => {
  const isDark = theme === 'dark';

  const styles = {
    primary: isDark 
        ? 'bg-slate-700 hover:bg-slate-600 text-white border-slate-600'
        : 'bg-slate-800 hover:bg-slate-700 text-white border-slate-800',
    secondary: isDark
        ? 'bg-slate-700/50 hover:bg-slate-700 text-slate-300 border-dashed border-slate-500'
        : 'bg-slate-100 hover:bg-slate-200 text-slate-600 border-dashed border-slate-300',
    danger: isDark
        ? 'bg-red-500/10 hover:bg-red-500/20 text-red-400 border-red-500/30'
        : 'bg-red-50 hover:bg-red-100 text-red-600 border-red-200',
  };

  return (
    <button
      type="button"
      onClick={onClick}
      className={`
        flex items-center justify-center gap-2 w-full py-2.5 px-4 rounded-lg text-sm font-medium border transition-all
        ${styles[variant as keyof typeof styles]}
      `}
    >
      {icon}
      {label}
    </button>
  );
};

export default Toolbar;

import React, { useRef, useEffect } from 'react';
import { GridData, ToolType, EMPTY_COLOR, BoardStyle, Language, Theme } from '../types';
import { translations } from '../utils/translations';

interface GridProps {
  grid: GridData;
  setGrid: React.Dispatch<React.SetStateAction<GridData>>;
  activeColor: string;
  setActiveColor: (c: string) => void;
  tool: ToolType;
  showGridLines: boolean;
  boardStyle: BoardStyle;
  beadSize: number;
  onStrokeEnd?: () => void;
  lang: Language;
  theme: Theme;
}

const Grid: React.FC<GridProps> = ({ 
  grid, 
  setGrid, 
  activeColor, 
  setActiveColor,
  tool, 
  showGridLines,
  boardStyle,
  beadSize,
  onStrokeEnd,
  lang,
  theme
}) => {
  const isDrawing = useRef(false);
  const t = translations[lang];
  const isDark = theme === 'dark';

  // Safety check: Ensure grid is populated before rendering
  if (!grid || grid.length === 0 || !grid[0]) {
    return (
        <div className={`flex items-center justify-center w-64 h-64 ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>
            {t.loading}
        </div>
    );
  }

  // Helper to paint a specific cell
  const paintCell = (rowIndex: number, colIndex: number) => {
    if (rowIndex < 0 || rowIndex >= grid.length || colIndex < 0 || colIndex >= grid[0].length) return;

    // Optimization: Don't update state if color is identical
    const currentColor = grid[rowIndex][colIndex];
    let targetColor = activeColor;

    if (tool === ToolType.ERASER) {
      targetColor = EMPTY_COLOR;
    } else if (tool === ToolType.EYEDROPPER) {
        if (currentColor !== EMPTY_COLOR) {
            setActiveColor(currentColor);
        }
        return; // Don't paint
    }

    if (currentColor === targetColor) return;

    setGrid(prev => {
      const newGrid = [...prev]; // Shallow copy outer
      newGrid[rowIndex] = [...prev[rowIndex]]; // Copy row
      newGrid[rowIndex][colIndex] = targetColor;
      return newGrid;
    });
  };

  const handleMouseDown = (r: number, c: number) => {
    isDrawing.current = true;
    paintCell(r, c);
  };

  const handleMouseEnter = (r: number, c: number) => {
    if (isDrawing.current) {
      paintCell(r, c);
    }
  };

  const handleMouseUp = () => {
    if (isDrawing.current) {
      isDrawing.current = false;
      if (onStrokeEnd) onStrokeEnd();
    }
  };

  // Global mouse up to catch drags that go outside
  useEffect(() => {
    const handleGlobalMouseUp = () => { 
        if (isDrawing.current) {
            isDrawing.current = false; 
            if (onStrokeEnd) onStrokeEnd();
        }
    };
    window.addEventListener('mouseup', handleGlobalMouseUp);
    return () => window.removeEventListener('mouseup', handleGlobalMouseUp);
  }, [onStrokeEnd]);

  const isBead = boardStyle === BoardStyle.BEAD;

  // Dynamic Styles
  const containerClass = isDark ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-200 shadow-slate-200';
  const gridLineClass = isDark ? 'border-slate-700/50' : 'border-slate-200';
  const emptyPegClass = isDark ? 'bg-slate-700 shadow-inner' : 'bg-slate-200 shadow-inner';
  const bgPatternColor = isDark ? '#1e293b' : '#e2e8f0';

  return (
    <div 
      className={`select-none inline-block shadow-2xl p-1 rounded-sm border transition-colors duration-300 ${containerClass}`}
      onMouseLeave={handleMouseUp}
      style={{
        display: 'grid',
        gridTemplateColumns: `repeat(${grid[0].length}, 1fr)`,
        gap: '0px', 
        // Force a max size to keep it within view
        maxWidth: '100%',
        maxHeight: '80vh',
        aspectRatio: '1 / 1',
        width: 'min(600px, 90vw)', 
      }}
    >
      {grid.map((row, rIndex) => (
        row.map((color, cIndex) => {
          const isTransparent = color === 'transparent' || color === EMPTY_COLOR;

          return (
            <div
              key={`${rIndex}-${cIndex}`}
              onMouseDown={() => handleMouseDown(rIndex, cIndex)}
              onMouseEnter={() => handleMouseEnter(rIndex, cIndex)}
              className={`
                w-full h-full cursor-crosshair flex items-center justify-center
                ${showGridLines && !isBead ? `border-[0.5px] ${gridLineClass}` : ''}
              `}
            >
                <div 
                   className={`
                      transition-all duration-200
                      ${isBead 
                          ? isTransparent 
                              ? `w-[20%] h-[20%] rounded-full ${emptyPegClass}` // Peg for empty bead
                              : 'rounded-full shadow-md ring-1 ring-black/10' // Filled Bead
                          : 'w-full h-full' // Square
                      }
                   `}
                   style={{ 
                      // Size logic: If Square, 100%. If Bead, use dynamic size unless it's an empty peg
                      width: isBead ? (isTransparent ? undefined : `${beadSize}%`) : undefined,
                      height: isBead ? (isTransparent ? undefined : `${beadSize}%`) : undefined,

                      backgroundColor: isBead && isTransparent ? undefined : (color === 'transparent' ? undefined : color),
                      backgroundImage: (!isBead && isTransparent)
                        ? `linear-gradient(45deg, ${bgPatternColor} 25%, transparent 25%), linear-gradient(-45deg, ${bgPatternColor} 25%, transparent 25%), linear-gradient(45deg, transparent 75%, ${bgPatternColor} 75%), linear-gradient(-45deg, transparent 75%, ${bgPatternColor} 75%)` 
                        : 'none',
                      backgroundSize: !isBead ? '10px 10px' : undefined,
                      backgroundPosition: !isBead ? '0 0, 0 5px, 5px -5px, -5px 0px' : undefined,
                      // Add nice 3D lighting effect for colored beads
                      boxShadow: (isBead && !isTransparent) 
                        ? 'inset -2px -2px 4px rgba(0,0,0,0.3), inset 2px 2px 4px rgba(255,255,255,0.25), 1px 1px 2px rgba(0,0,0,0.5)' 
                        : undefined
                   }}
                />
            </div>
          );
        })
      ))}
    </div>
  );
};

export default Grid;

import React, { useState } from 'react';
import { AlertTriangle, X } from 'lucide-react';
import { Language, Theme } from '../types';
import { translations } from '../utils/translations';

interface ClearConfirmationModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (dontShowAgain: boolean) => void;
  lang: Language;
  theme?: Theme;
}

const ClearConfirmationModal: React.FC<ClearConfirmationModalProps> = ({ isOpen, onClose, onConfirm, lang, theme = 'dark' }) => {
  const [dontShowAgain, setDontShowAgain] = useState(false);
  const t = translations[lang];
  const isDark = theme === 'dark';

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
      <div className={`
        border rounded-2xl w-full max-w-sm shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200
        ${isDark ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-200'}
      `}>
        <div className={`
            flex justify-between items-center p-4 border-b
            ${isDark ? 'border-slate-700 bg-slate-800/50' : 'border-slate-100 bg-slate-50/80'}
        `}>
          <h3 className={`text-lg font-semibold flex items-center gap-2 ${isDark ? 'text-white' : 'text-slate-800'}`}>
            <AlertTriangle className="text-red-400" size={20} />
            {t.clearConfirmTitle}
          </h3>
          <button 
            type="button"
            onClick={onClose}
            className={`transition-colors ${isDark ? 'text-slate-400 hover:text-white' : 'text-slate-500 hover:text-slate-800'}`}
          >
            <X size={20} />
          </button>
        </div>

        <div className="p-6">
          <p className={`mb-6 ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>
            {t.clearConfirmText}
          </p>

          <label className={`flex items-center gap-2 text-sm mb-6 cursor-pointer hover:opacity-80 ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>
            <input 
              type="checkbox"
              checked={dontShowAgain}
              onChange={(e) => setDontShowAgain(e.target.checked)}
              className="w-4 h-4 rounded border-slate-600 bg-slate-700 text-blue-600 focus:ring-blue-500/50 focus:ring-offset-0"
            />
            {t.dontAskAgain}
          </label>

          <div className="flex justify-end gap-3">
             <button
              type="button"
              onClick={onClose}
              className={`px-4 py-2 text-sm rounded-lg transition-colors ${isDark ? 'text-slate-300 hover:text-white hover:bg-slate-700' : 'text-slate-600 hover:text-slate-800 hover:bg-slate-100'}`}
            >
              {t.cancel}
            </button>
            <button
              type="button"
              onClick={() => onConfirm(dontShowAgain)}
              className="px-6 py-2 bg-red-500 hover:bg-red-600 text-white rounded-lg text-sm font-medium transition-colors shadow-lg shadow-red-500/20"
            >
              {t.clear_board_btn}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ClearConfirmationModal;

import React, { useState, useEffect, useCallback } from 'react';
import { Undo2, Redo2, Languages, Settings as SettingsIcon } from 'lucide-react';
import Grid from './components/Grid';
import Toolbar from './components/Toolbar';
import ClearConfirmationModal from './components/ClearConfirmationModal';
import SettingsModal from './components/SettingsModal';
import { GridData, ToolType, DEFAULT_COLOR, EMPTY_COLOR, BoardStyle, Language, Theme } from './types';
import { processImageToGrid, exportGridToImage } from './utils/imageHelper';
import { translations } from './utils/translations';

// Helper to create a fresh grid
const createGrid = (size: number): GridData => {
  return Array(size).fill(null).map(() => Array(size).fill(EMPTY_COLOR));
};

const App: React.FC = () => {
  // Language & Theme State
  const [lang, setLang] = useState<Language>('zh');
  const [theme, setTheme] = useState<Theme>('dark');

  // State
  const [gridSize, setGridSize] = useState<number>(16);
  // Initialize grid immediately with the default size
  const [grid, setGrid] = useState<GridData>(() => createGrid(16));
  const [activeColor, setActiveColor] = useState<string>(DEFAULT_COLOR);
  const [tool, setTool] = useState<ToolType>(ToolType.PEN);
  const [showGridLines, setShowGridLines] = useState<boolean>(true);
  const [boardStyle, setBoardStyle] = useState<BoardStyle>(BoardStyle.SQUARE);
