import { GridData } from '../types';
import { rgbToHex } from './colorUtils';

interface RGB { r: number; g: number; b: number; }

// Euclidean distance between two colors
const colorDistance = (c1: RGB, c2: RGB) => {
  return Math.sqrt((c1.r - c2.r) ** 2 + (c1.g - c2.g) ** 2 + (c1.b - c2.b) ** 2);
};

// Simple K-Means implementation
const runKMeans = (pixels: RGB[], k: number): RGB[] => {
  // If we have fewer pixels than K, just return unique pixels
  if (pixels.length <= k) return pixels;

  // 1. Initialize centroids (Pick K random pixels)
  let centroids: RGB[] = [];
  for (let i = 0; i < k; i++) {
    centroids.push(pixels[Math.floor(Math.random() * pixels.length)]);
  }

  const maxIterations = 15; // Sufficient for this use case

  for (let iter = 0; iter < maxIterations; iter++) {
    const clusters: RGB[][] = Array.from({ length: k }, () => []);

    // 2. Assign each pixel to the nearest centroid
    for (const p of pixels) {
      let minIdx = 0;
      let minDist = Infinity;
      for (let i = 0; i < k; i++) {
        const d = colorDistance(p, centroids[i]);
        if (d < minDist) {
          minDist = d;
          minIdx = i;
        }
      }
      clusters[minIdx].push(p);
    }

    // 3. Recalculate centroids
    let converged = true;
    const newCentroids = clusters.map((cluster, i) => {
      if (cluster.length === 0) return centroids[i]; // Keep old centroid if cluster is empty

      const sum = cluster.reduce((acc, c) => ({ 
        r: acc.r + c.r, 
        g: acc.g + c.g, 
        b: acc.b + c.b 
      }), { r: 0, g: 0, b: 0 });

      const newC = {
        r: Math.round(sum.r / cluster.length),
        g: Math.round(sum.g / cluster.length),
        b: Math.round(sum.b / cluster.length)
      };

      if (newC.r !== centroids[i].r || newC.g !== centroids[i].g || newC.b !== centroids[i].b) {
        converged = false;
      }
      return newC;
    });

    centroids = newCentroids;
    if (converged) break;
  }

  return centroids;
};

/**
 * Processes an uploaded image file and converts it into a pixel grid.
 * It resizes the image to match the target grid dimensions and applies K-Means clustering.
 */
export const processImageToGrid = (
  file: File,
  rows: number,
  cols: number,
  paletteSize: number = 16
): Promise<GridData> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');

        if (!ctx) {
          reject(new Error('Could not get canvas context'));
          return;
        }

        // Set canvas size to the grid dimensions
        canvas.width = cols;
        canvas.height = rows;

        // Draw and resize image
        ctx.drawImage(img, 0, 0, cols, rows);

        // Extract pixel data
        const imageData = ctx.getImageData(0, 0, cols, rows);
        const data = imageData.data;

        // 1. Collect all non-transparent pixels for clustering
        const validPixels: RGB[] = [];
        for (let i = 0; i < data.length; i += 4) {
            // Alpha check (> 50/255)
            if (data[i + 3] >= 50) {
                validPixels.push({ r: data[i], g: data[i + 1], b: data[i + 2] });
            }
        }

        // 2. Run K-Means to find representative colors
        let centroids: RGB[] = [];
        if (validPixels.length > 0) {
            centroids = runKMeans(validPixels, paletteSize);
        }

        const newGrid: GridData = [];

        // 3. Construct the grid, mapping each pixel to the nearest centroid
        for (let y = 0; y < rows; y++) {
          const row: string[] = [];
          for (let x = 0; x < cols; x++) {
            const index = (y * cols + x) * 4;
            const r = data[index];
            const g = data[index + 1];
            const b = data[index + 2];
            const a = data[index + 3];

            // If fully transparent, use transparent string
            if (a < 50) {
              row.push('transparent');
            } else {
              // Find nearest color from centroids
              const currentPixel = { r, g, b };
              let nearest = currentPixel;

              if (centroids.length > 0) {
                  let minD = Infinity;
                  for (const c of centroids) {
                      const d = colorDistance(currentPixel, c);
                      if (d < minD) {
                          minD = d;
                          nearest = c;
                      }
                  }
              }

              row.push(rgbToHex(nearest.r, nearest.g, nearest.b));
            }
          }
          newGrid.push(row);
        }
        resolve(newGrid);
      };
      img.onerror = reject;
      img.src = event.target?.result as string;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Exports the current grid to a high-res PNG image.
 */
export const exportGridToImage = (grid: GridData, scale: number = 20) => {
  const rows = grid.length;
  const cols = grid[0].length;

  const canvas = document.createElement('canvas');
  canvas.width = cols * scale;
  canvas.height = rows * scale;

  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  grid.forEach((row, y) => {
    row.forEach((color, x) => {
      if (color !== 'transparent') {
        ctx.fillStyle = color;
        ctx.fillRect(x * scale, y * scale, scale, scale);
      }
    });
  });

  const link = document.createElement('a');
  link.download = `pixel-art-${Date.now()}.png`;
  link.href = canvas.toDataURL('image/png');
  link.click();
};

import React, { useRef, useState, useEffect } from 'react';
