import { GridData } from '../types';
import { rgbToHex } from './colorUtils';

/**
 * Processes an uploaded image file and converts it into a pixel grid.
 * It resizes the image to fit within the target grid dimensions while maintaining aspect ratio.
 */
export const processImageToGrid = (
  file: File,
  rows: number,
  cols: number
): Promise<GridData> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');

        if (!ctx) {
          reject(new Error('Could not get canvas context'));
          return;
        }

        // Set canvas size to the grid dimensions
        canvas.width = cols;
        canvas.height = rows;

        // Clear canvas to ensure transparent background
        ctx.clearRect(0, 0, cols, rows);

        // Calculate scale to fit within dimensions while maintaining aspect ratio
        const scale = Math.min(cols / img.width, rows / img.height);
        const w = img.width * scale;
        const h = img.height * scale;

        // Calculate centered position
        const x = (cols - w) / 2;
        const y = (rows - h) / 2;

        // Draw image centered and scaled
        ctx.drawImage(img, x, y, w, h);

        // Extract pixel data
        const imageData = ctx.getImageData(0, 0, cols, rows);
        const data = imageData.data;
        const newGrid: GridData = [];

        for (let rIndex = 0; rIndex < rows; rIndex++) {
          const row: string[] = [];
          for (let cIndex = 0; cIndex < cols; cIndex++) {
            const index = (rIndex * cols + cIndex) * 4;
            const r = data[index];
            const g = data[index + 1];
            const b = data[index + 2];
            const a = data[index + 3];

            // If fully transparent (or close to it), use transparent string, else hex
            if (a < 50) {
              row.push('transparent');
            } else {
              row.push(rgbToHex(r, g, b));
            }
          }
          newGrid.push(row);
        }
        resolve(newGrid);
      };
      img.onerror = reject;
      img.src = event.target?.result as string;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Exports the current grid to a high-res PNG image.
 */
export const exportGridToImage = (grid: GridData, scale: number = 20) => {
  const rows = grid.length;
  const cols = grid[0].length;

  const canvas = document.createElement('canvas');
  canvas.width = cols * scale;
  canvas.height = rows * scale;

  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  grid.forEach((row, y) => {
    row.forEach((color, x) => {
      if (color !== 'transparent') {
        ctx.fillStyle = color;
        ctx.fillRect(x * scale, y * scale, scale, scale);
      }
    });
  });

  const link = document.createElement('a');
  link.download = `pixel-art-${Date.now()}.png`;
  link.href = canvas.toDataURL('image/png');
  link.click();
};

// Converts RGB to Hex
export const rgbToHex = (r: number, g: number, b: number): string => {
  return "#" + ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1);
};

// Converts Hex to RGB
export const hexToRgb = (hex: string) => {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16)
  } : null;
};

interface RGB { r: number; g: number; b: number; }

// Weighted Euclidean distance for colors (approximating human perception)
const colorDistance = (rgb1: RGB, rgb2: RGB): number => {
  const R_1 = rgb1.r;
  const G_1 = rgb1.g;
  const B_1 = rgb1.b;
  const R_2 = rgb2.r;
  const G_2 = rgb2.g;
  const B_2 = rgb2.b;

  const rmean = (R_1 + R_2) / 2;
  const R = R_1 - R_2;
  const G = G_1 - G_2;
  const B = B_1 - B_2;

  // Formula provided: sqrt((2+rmean/256)*(R^2) + 4*(G^2) + (2+(255-rmean)/256)*(B^2))
  return Math.sqrt((2 + rmean / 256) * (R ** 2) + 4 * (G ** 2) + (2 + (255 - rmean) / 256) * (B ** 2));
};

// Base colors for categorization
const BASE_COLORS: RGB[] = [
  { r: 255, g: 0, b: 0 },       // Red
  { r: 255, g: 192, b: 203 },   // Pink
  { r: 255, g: 165, b: 0 },     // Orange
  { r: 0, g: 0, b: 255 },       // Blue
  { r: 0, g: 128, b: 0 },       // Green
  { r: 128, g: 0, b: 128 },     // Purple
  { r: 255, g: 255, b: 0 },     // Yellow
  { r: 0, g: 0, b: 0 },         // Black
  { r: 255, g: 255, b: 255 },   // White
  { r: 165, g: 42, b: 42 },     // Brown
];

/**
 * Reduces the grid colors by categorizing pixels into base colors
 * and replacing them with the average color of that category.
 */
export const reduceGridToAverageColors = (grid: string[][]): string[][] => {
  // Deep copy grid
  const newGrid = grid.map(row => [...row]);
  const rows = newGrid.length;
  if (rows === 0) return newGrid;
  const cols = newGrid[0].length;

  // Buckets for each base color
  const buckets = BASE_COLORS.map(() => ({
    sumR: 0,
    sumG: 0,
    sumB: 0,
    count: 0,
    pixels: [] as { r: number, c: number }[]
  }));

  // 1. Categorize pixels
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const color = newGrid[r][c];
      if (color === 'transparent') continue;

      const rgb = hexToRgb(color);
      if (!rgb) continue;

      let minDist = Infinity;
      let minIndex = -1;

      for (let i = 0; i < BASE_COLORS.length; i++) {
        const dist = colorDistance(rgb, BASE_COLORS[i]);
        if (dist < minDist) {
          minDist = dist;
          minIndex = i;
        }
      }

      if (minIndex !== -1) {
        buckets[minIndex].pixels.push({ r, c });
        buckets[minIndex].sumR += rgb.r;
        buckets[minIndex].sumG += rgb.g;
        buckets[minIndex].sumB += rgb.b;
        buckets[minIndex].count++;
      }
    }
  }

  // 2. Calculate average and replace
  buckets.forEach(bucket => {
    if (bucket.count > 0) {
      const avgR = Math.round(bucket.sumR / bucket.count);
      const avgG = Math.round(bucket.sumG / bucket.count);
      const avgB = Math.round(bucket.sumB / bucket.count);
      const avgHex = rgbToHex(avgR, avgG, avgB);

      bucket.pixels.forEach(p => {
        newGrid[p.r][p.c] = avgHex;
      });
    }
  });

  return newGrid;
};

