  setShowGridLines: (v: boolean) => void;
  boardStyle: BoardStyle;
  setBoardStyle: (s: BoardStyle) => void;
  beadSize: number;
  setBeadSize: (s: number) => void;
  lang: Language;
  theme: Theme;
}

const Toolbar: React.FC<ToolbarProps> = ({
  tool, setTool,
  activeColor, setActiveColor,
  gridSize, setGridSize,
  onClear,
  onDownload,
  onUpload,
  onSimplifyColors,
  showGridLines, setShowGridLines,
  boardStyle, setBoardStyle,
  beadSize, setBeadSize,
  lang,
  theme
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isDark = theme === 'dark';

  // Local state for the custom input to allow typing
  const [customSize, setCustomSize] = useState<string>(gridSize.toString());

  // Recent Colors State
  const [recentColors, setRecentColors] = useState<string[]>([]);
  const [showRecent, setShowRecent] = useState<boolean>(true);

  const t = translations[lang];

  // Sync local input when external grid size changes
  useEffect(() => {
    setCustomSize(gridSize.toString());
  }, [gridSize]);

  // Track active color usage for history
  useEffect(() => {
    if (!activeColor || activeColor === 'transparent') return;

    const handler = setTimeout(() => {
      setRecentColors(prev => {
        // If the color is already the most recent, do nothing
        if (prev[0] === activeColor) return prev;
        // Otherwise, move it to front or add it
        const filtered = prev.filter(c => c !== activeColor);
        return [activeColor, ...filtered].slice(0, 12); // Limit to 12 colors
      });
    }, 500); // Debounce to capture final color after picking

    return () => clearTimeout(handler);
  }, [activeColor]);

  const handleCustomSizeCommit = () => {
    let val = parseInt(customSize, 10);

    if (isNaN(val)) {
      setCustomSize(gridSize.toString());
      return;
    }

    // Enforce limits 4 - 40
    if (val < 4) val = 4;
    if (val > 40) val = 40;

    setCustomSize(val.toString());
    if (val !== gridSize) {
      setGridSize(val);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleCustomSizeCommit();
      (e.target as HTMLInputElement).blur();
    }
  };

  const colors = [
    '#000000', '#1a1c2c', '#5d275d', '#b13e53', '#ef7d57',
    '#ffcd75', '#a7f070', '#38b764', '#257179', '#29366f',
    '#3b5dc9', '#41a6f6', '#73eff7', '#f4f4f4', '#94b0c2',
    '#566c86', '#333c57'
  ];

  const handleFileClick = () => {
    fileInputRef.current?.click();
  };

  // Styles based on theme
  const containerClass = isDark 
    ? 'bg-slate-800/50 border-slate-700 text-slate-100' 
    : 'bg-white/80 border-slate-200 text-slate-800 shadow-slate-200';

  const labelClass = isDark ? 'text-slate-400' : 'text-slate-500';

  const inputContainerClass = isDark 
    ? 'bg-slate-900/50 border-slate-700/50' 
    : 'bg-slate-100 border-slate-200';

  const inputTextClass = isDark ? 'text-white' : 'text-slate-800';

  const btnBaseClass = isDark 
    ? 'bg-slate-700 text-slate-400 border-slate-600 hover:bg-slate-600 hover:text-slate-200' 
    : 'bg-slate-100 text-slate-500 border-slate-200 hover:bg-slate-200 hover:text-slate-800';

  const btnActiveClass = isDark 
    ? 'bg-blue-600 border-blue-500 text-white shadow-lg shadow-blue-500/20' 
    : 'bg-blue-500 border-blue-400 text-white shadow-lg shadow-blue-500/20';

  return (
    <div className={`flex flex-col gap-6 p-5 backdrop-blur-xl border rounded-2xl shadow-xl w-full max-w-xs h-fit overflow-y-auto max-h-[90vh] transition-colors duration-300 ${containerClass}`}>

      {/* --- Size Selector --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>
          {t.size_label}
        </label>
        <div className="flex flex-col gap-3">
          <div className="flex flex-wrap gap-2">
            {PRESETS.map(size => (
              <button
                key={size}
                type="button"
                onClick={() => setGridSize(size)}
                className={`
                  flex-1 px-3 py-1.5 text-sm font-medium rounded-md border transition-all
                  ${gridSize === size ? btnActiveClass : btnBaseClass}
                `}
              >
                {size}
              </button>
            ))}
          </div>

          {/* Custom Input */}
          <div className={`flex items-center gap-2 p-2 rounded-lg border ${inputContainerClass}`}>
             <span className={`text-xs font-medium whitespace-nowrap px-1 ${labelClass}`}>{t.custom_size}:</span>
             <input 
                type="number"
                min={4}
                max={40}
                value={customSize}
                onChange={(e) => setCustomSize(e.target.value)}
                onBlur={handleCustomSizeCommit}
                onKeyDown={handleKeyDown}
                className={`w-full bg-transparent text-sm text-right focus:outline-none placeholder-slate-400 ${inputTextClass}`}
                placeholder="4-40"
             />
             <span className="text-xs text-slate-400 pr-1">px</span>
          </div>
        </div>
      </div>

      {/* --- Board Style --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>{t.board_style}</label>
        <div className="grid grid-cols-2 gap-2">
           <ToolButton 
             active={boardStyle === BoardStyle.SQUARE}
             onClick={() => setBoardStyle(BoardStyle.SQUARE)}
             icon={<Square size={18} />}
             label={t.style_square}
             theme={theme}
           />
           <ToolButton 
             active={boardStyle === BoardStyle.BEAD}
             onClick={() => setBoardStyle(BoardStyle.BEAD)}
             icon={<Circle size={18} />}
             label={t.style_bead}
             theme={theme}
           />
        </div>

        {/* Bead Size Slider - Only visible in Bead mode */}
        {boardStyle === BoardStyle.BEAD && (
            <div className={`mt-3 p-2 rounded-lg border animate-in fade-in slide-in-from-top-2 duration-200 ${isDark ? 'bg-slate-900/30 border-slate-700/30' : 'bg-slate-50 border-slate-200'}`}>
                <div className="flex justify-between items-center mb-1">
                    <span className="text-[10px] uppercase font-bold text-slate-500">{t.bead_diameter}</span>
                    <span className={`text-xs font-mono ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>{beadSize}%</span>
                </div>
                <input 
                    type="range" 
                    min="20" 
                    max="100" 
                    step="5"
                    value={beadSize}
                    onChange={(e) => setBeadSize(Number(e.target.value))}
                    className={`w-full h-1.5 rounded-lg appearance-none cursor-pointer accent-blue-500 hover:accent-blue-400 ${isDark ? 'bg-slate-700' : 'bg-slate-300'}`}
                />
            </div>
        )}
      </div>

      {/* --- Tools --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>{t.tools_label}</label>
        <div className="grid grid-cols-4 gap-2">
          <ToolButton 
            active={tool === ToolType.PEN} 
            onClick={() => setTool(ToolType.PEN)} 
            icon={<Pencil size={18} />} 
            label={t.tool_pen}
            theme={theme}
          />
          <ToolButton 
            active={tool === ToolType.ERASER} 
            onClick={() => setTool(ToolType.ERASER)} 
            icon={<Eraser size={18} />} 
            label={t.tool_eraser}
            theme={theme}
          />
          <ToolButton 
            active={tool === ToolType.EYEDROPPER} 
            onClick={() => setTool(ToolType.EYEDROPPER)} 
            icon={<Pipette size={18} />} 
            label={t.tool_pick}
            theme={theme}
          />
          <ToolButton 
            active={showGridLines} 
            onClick={() => setShowGridLines(!showGridLines)} 
            icon={<Grid3X3 size={18} />} 
            label={t.tool_grid}
            theme={theme}
          />
        </div>
      </div>

      {/* --- Colors --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>{t.palette_label}</label>
        <div className="grid grid-cols-6 gap-2 mb-3">
          {colors.map(c => (
            <button
              key={c}
              type="button"
              onClick={() => setActiveColor(c)}
              className={`
                w-8 h-8 rounded-full border-2 transition-transform hover:scale-110
                ${activeColor === c ? 'border-white ring-2 ring-blue-500' : 'border-transparent'}
              `}
              style={{ backgroundColor: c }}
            />
          ))}
        </div>
        <div className={`flex items-center gap-2 p-2 rounded-lg ${isDark ? 'bg-slate-700/50' : 'bg-slate-200/50'}`}>
          <input 
            type="color" 
            value={activeColor}
            onChange={(e) => setActiveColor(e.target.value)}
            className="w-8 h-8 rounded cursor-pointer bg-transparent border-none p-0"
          />
          <span className={`text-xs font-mono uppercase ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>{activeColor}</span>
        </div>
      </div>

      {/* --- Recent Colors --- */}
      {recentColors.length > 0 && (
          <div className={`pt-2 border-t ${isDark ? 'border-slate-700/50' : 'border-slate-200'}`}>
            <button 
                type="button"
                onClick={() => setShowRecent(!showRecent)}
                className={`flex items-center justify-between w-full text-xs font-semibold uppercase tracking-wider mb-2 transition-colors ${isDark ? 'text-slate-400 hover:text-slate-300' : 'text-slate-500 hover:text-slate-700'}`}
            >
                <span className="flex items-center gap-1.5">
                    <Clock size={12} />
                    {t.recent_label}
                </span>
                {showRecent ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
            </button>

            {showRecent && (
                <div className="grid grid-cols-6 gap-2 mb-3 animate-in fade-in slide-in-from-top-1 duration-200">
                {recentColors.map(c => (
                    <button
                    key={c}
                    type="button"
                    onClick={() => setActiveColor(c)}
                    className={`
                        w-8 h-8 rounded-full border-2 transition-transform hover:scale-110 shadow-sm
                        ${activeColor === c ? 'border-white ring-2 ring-blue-500/50' : (isDark ? 'border-slate-600/50' : 'border-slate-300')}
                    `}
                    style={{ backgroundColor: c }}
                    title={c}
                    />
                ))}
                </div>
            )}
          </div>
      )}

      {/* --- Actions --- */}
      <div className={`space-y-3 pt-4 border-t ${isDark ? 'border-slate-700' : 'border-slate-200'}`}>

        <input 
          type="file" 
          ref={fileInputRef}
          onChange={onUpload}
          accept="image/*"
          className="hidden" 
        />

        <ActionButton 
          onClick={handleFileClick} 
          icon={<ImageIcon size={18} />} 
          label={t.upload_image} 
          variant="secondary"
          theme={theme}
        />

        <ActionButton 
          onClick={onSimplifyColors}
          icon={<Palette size={18} />}
          label={t.simplify_colors}
          variant="secondary"
          theme={theme}
        />

        <div className="grid grid-cols-2 gap-2">
            <ActionButton 
                onClick={onClear} 
                icon={<Trash2 size={18} />} 
                label={t.clear} 
                variant="danger"
                theme={theme}
            />
            <ActionButton 
                onClick={onDownload} 
                icon={<Download size={18} />} 
                label={t.save_image} 
                variant="primary"
                theme={theme}
            />
        </div>
      </div>
    </div>
  );
};

// --- Sub-components for styling ---

const ToolButton = ({ active, onClick, icon, label, theme }: any) => {
  const isDark = theme === 'dark';
  return (
    <button
      type="button"
      onClick={onClick}
      title={label}
      className={`
        flex items-center justify-center gap-2 p-3 rounded-xl transition-all
        ${active 
          ? (isDark ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/25' : 'bg-blue-500 text-white shadow-lg shadow-blue-500/25')
          : (isDark ? 'bg-slate-700 text-slate-400 hover:bg-slate-600 hover:text-slate-200' : 'bg-slate-100 text-slate-500 hover:bg-slate-200 hover:text-slate-800')}
      `}
    >
      {icon}
    </button>
  );
};

const ActionButton = ({ onClick, icon, label, variant = 'primary', theme }: any) => {
  const isDark = theme === 'dark';

  const styles = {
    primary: isDark 
        ? 'bg-slate-700 hover:bg-slate-600 text-white border-slate-600'
        : 'bg-slate-800 hover:bg-slate-700 text-white border-slate-800',
    secondary: isDark
        ? 'bg-slate-700/50 hover:bg-slate-700 text-slate-300 border-dashed border-slate-500'
        : 'bg-slate-100 hover:bg-slate-200 text-slate-600 border-dashed border-slate-300',
    danger: isDark
        ? 'bg-red-500/10 hover:bg-red-500/20 text-red-400 border-red-500/30'
        : 'bg-red-50 hover:bg-red-100 text-red-600 border-red-200',
  };

  return (
    <button
      type="button"
      onClick={onClick}
      className={`
        flex items-center justify-center gap-2 w-full py-2.5 px-4 rounded-lg text-sm font-medium border transition-all
        ${styles[variant as keyof typeof styles]}
      `}
    >
      {icon}
      {label}
    </button>
  );
};

export default Toolbar;

import React, { useState, useEffect, useCallback } from 'react';
import { Undo2, Redo2, Languages, Settings as SettingsIcon } from 'lucide-react';
import Grid from './components/Grid';
import Toolbar from './components/Toolbar';
import ClearConfirmationModal from './components/ClearConfirmationModal';
import SettingsModal from './components/SettingsModal';
import { GridData, ToolType, DEFAULT_COLOR, EMPTY_COLOR, BoardStyle, Language, Theme } from './types';
import { processImageToGrid, exportGridToImage } from './utils/imageHelper';
import { reduceGridToAverageColors } from './utils/colorUtils';
import { translations } from './utils/translations';

// Helper to create a fresh grid
const createGrid = (size: number): GridData => {
  return Array(size).fill(null).map(() => Array(size).fill(EMPTY_COLOR));
};

const App: React.FC = () => {
  // Language & Theme State
  const [lang, setLang] = useState<Language>('zh');
  const [theme, setTheme] = useState<Theme>('dark');

  // State
  const [gridSize, setGridSize] = useState<number>(16);
  // Initialize grid immediately with the default size
  const [grid, setGrid] = useState<GridData>(() => createGrid(16));
  const [activeColor, setActiveColor] = useState<string>(DEFAULT_COLOR);
  const [tool, setTool] = useState<ToolType>(ToolType.PEN);
  const [showGridLines, setShowGridLines] = useState<boolean>(true);
  const [boardStyle, setBoardStyle] = useState<BoardStyle>(BoardStyle.SQUARE);
  const [beadSize, setBeadSize] = useState<number>(85); // Percentage 20-100

  // History State
  const [history, setHistory] = useState<GridData[]>([]);
  const [historyIndex, setHistoryIndex] = useState<number>(-1);

  // Modal States
  const [isClearModalOpen, setIsClearModalOpen] = useState(false);
  const [skipClearConfirm, setSkipClearConfirm] = useState(false);
  const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);

  // Get current translations
  const t = translations[lang];
  const isDark = theme === 'dark';

  // Initialize history on first load or reset
  useEffect(() => {
    const initialGrid = createGrid(gridSize);
    setGrid(initialGrid);
    setHistory([initialGrid]);
    setHistoryIndex(0);
  }, [gridSize]); // Reset everything when grid size changes

  // History Helper: Add current grid state to history
  const addToHistory = useCallback((newGridState: GridData) => {
    setHistory(prev => {
      const newHistory = prev.slice(0, historyIndex + 1);
      // Deep copy to ensure history immutability
      const copy = JSON.parse(JSON.stringify(newGridState));
      newHistory.push(copy);
      return newHistory;
    });
    setHistoryIndex(prev => prev + 1);
  }, [historyIndex]);

  // Handle Undo
  const handleUndo = () => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      setHistoryIndex(newIndex);
      setGrid(JSON.parse(JSON.stringify(history[newIndex])));
    }
  };

  // Handle Redo
  const handleRedo = () => {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      setHistoryIndex(newIndex);
      setGrid(JSON.parse(JSON.stringify(history[newIndex])));
    }
  };

  // Handlers
  const handleStrokeEnd = () => {
    addToHistory(grid);
  };

  // Logic to actually perform the clear operation
  const performClear = () => {
    const newGrid = createGrid(gridSize);
    setGrid(newGrid);
    addToHistory(newGrid);
    setIsClearModalOpen(false);
  };

  // Triggered when user clicks "Clear" in toolbar
  const handleClearRequest = () => {
    if (skipClearConfirm) {
        performClear();
    } else {
        setIsClearModalOpen(true);
    }
  };

  // Triggered when user confirms in the modal
  const handleConfirmClear = (dontShowAgain: boolean) => {
    if (dontShowAgain) {
        setSkipClearConfirm(true);
    }
    performClear();
  };

  const handleDownload = () => {
    exportGridToImage(grid);
  };

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const newGrid = await processImageToGrid(file, gridSize, gridSize);
      setGrid(newGrid);
      addToHistory(newGrid);
      // Reset file input
      e.target.value = '';
    } catch (error) {
      console.error("Failed to process image", error);
      alert(t.error_processing_alert);
    }
  };

  const handleSimplifyColors = () => {
    const newGrid = reduceGridToAverageColors(grid);
    setGrid(newGrid);
    addToHistory(newGrid);
  };

  const toggleLanguage = () => {
    setLang(prev => prev === 'zh' ? 'en' : 'zh');
  };

  return (
    <div className={`min-h-screen flex flex-col items-center justify-center p-4 md:p-8 relative overflow-hidden transition-colors duration-500 ${isDark ? 'bg-slate-900 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>

      {/* Background decoration */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0">
         <div className={`absolute top-[-20%] left-[-10%] w-[50%] h-[50%] rounded-full blur-[120px] transition-colors duration-500 ${isDark ? 'bg-blue-600/10' : 'bg-blue-400/20'}`}></div>
         <div className={`absolute bottom-[-20%] right-[-10%] w-[50%] h-[50%] rounded-full blur-[120px] transition-colors duration-500 ${isDark ? 'bg-purple-600/10' : 'bg-purple-400/20'}`}></div>
      </div>

      <header className="mb-8 z-10 text-center relative w-full max-w-6xl">
        {/* Desktop Controls */}
        <div className="absolute right-0 top-0 hidden md:flex items-center gap-2">
            <button 
                onClick={toggleLanguage}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full border transition-colors text-xs font-medium ${isDark ? 'bg-slate-800 border-slate-700 hover:bg-slate-700 text-slate-300' : 'bg-white border-slate-200 hover:bg-slate-50 text-slate-600'}`}
            >
                <Languages size={14} />
                {lang === 'zh' ? 'EN' : '中文'}
            </button>
            <button 
                onClick={() => setIsSettingsModalOpen(true)}
                className={`p-1.5 rounded-full border transition-colors ${isDark ? 'bg-slate-800 border-slate-700 hover:bg-slate-700 text-slate-300' : 'bg-white border-slate-200 hover:bg-slate-50 text-slate-600'}`}
            >
                <SettingsIcon size={14} />
            </button>
        </div>

        {/* Mobile Controls */}
        <div className="absolute right-0 top-[-10px] md:hidden flex gap-2">
            <button 
                onClick={toggleLanguage}
                className={`p-2 rounded-full border transition-colors ${isDark ? 'bg-slate-800 border-slate-700 hover:bg-slate-700 text-slate-300' : 'bg-white border-slate-200 hover:bg-slate-50 text-slate-600'}`}
            >
                <Languages size={16} />
            </button>
             <button 
                onClick={() => setIsSettingsModalOpen(true)}
                className={`p-2 rounded-full border transition-colors ${isDark ? 'bg-slate-800 border-slate-700 hover:bg-slate-700 text-slate-300' : 'bg-white border-slate-200 hover:bg-slate-50 text-slate-600'}`}
            >
                <SettingsIcon size={16} />
            </button>
        </div>

        <h1 className="text-4xl md:text-5xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-purple-400 mb-2">
          {t.title}
        </h1>
        <p className={isDark ? "text-slate-400" : "text-slate-500"}>{t.subtitle}</p>
      </header>

      <main className="w-full max-w-6xl z-10 flex flex-col md:flex-row gap-8 items-start justify-center">

        {/* Left Control Panel (Mobile: Top) */}
        <section className="w-full md:w-auto order-2 md:order-1 flex justify-center">
          <Toolbar 
            tool={tool}
            setTool={setTool}
            activeColor={activeColor}
            setActiveColor={setActiveColor}
            gridSize={gridSize}
            setGridSize={setGridSize}
            onClear={handleClearRequest}
            onDownload={handleDownload}
            onUpload={handleUpload}
            onSimplifyColors={handleSimplifyColors}
            showGridLines={showGridLines}
            setShowGridLines={setShowGridLines}
            boardStyle={boardStyle}
            setBoardStyle={setBoardStyle}
            beadSize={beadSize}
            setBeadSize={setBeadSize}
            lang={lang}
            theme={theme}
          />
        </section>

        {/* Center Canvas */}
        <section className={`flex-1 order-1 md:order-2 p-4 md:p-8 rounded-3xl border shadow-2xl backdrop-blur-sm flex flex-col items-center transition-colors duration-300 ${isDark ? 'bg-slate-800/30 border-slate-700/50' : 'bg-white/60 border-slate-200'}`}>

           {/* Canvas Header (Undo/Redo) */}
           <div className="w-full flex justify-end gap-2 mb-4">
              <button 
                type="button"
                onClick={handleUndo}
                disabled={historyIndex <= 0}
                className={`p-2 rounded-lg transition-colors disabled:opacity-30 ${isDark ? 'bg-slate-700 hover:bg-slate-600 text-slate-200 disabled:hover:bg-slate-700' : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 disabled:hover:bg-white'}`}
                title={t.undo}
              >
                <Undo2 size={20} />
              </button>
              <button 
                type="button"
                onClick={handleRedo}
                disabled={historyIndex >= history.length - 1}
                className={`p-2 rounded-lg transition-colors disabled:opacity-30 ${isDark ? 'bg-slate-700 hover:bg-slate-600 text-slate-200 disabled:hover:bg-slate-700' : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 disabled:hover:bg-white'}`}
                title={t.redo}
              >
                <Redo2 size={20} />
              </button>
           </div>

           <Grid 
             grid={grid}
             setGrid={setGrid}
             activeColor={activeColor}
             setActiveColor={setActiveColor}
             tool={tool}
             showGridLines={showGridLines}
             boardStyle={boardStyle}
             beadSize={beadSize}
             onStrokeEnd={handleStrokeEnd}
             lang={lang}
             theme={theme}
           />
        </section>

      </main>

      <footer className={`mt-12 text-sm z-10 ${isDark ? 'text-slate-600' : 'text-slate-400'}`}>
        <p>{t.footer_text}</p>
      </footer>

      {/* Modals */}
      <ClearConfirmationModal 
        isOpen={isClearModalOpen}
        onClose={() => setIsClearModalOpen(false)}
        onConfirm={handleConfirmClear}
        lang={lang}
        theme={theme}
      />

      <SettingsModal 
        isOpen={isSettingsModalOpen}
        onClose={() => setIsSettingsModalOpen(false)}
        theme={theme}
        setTheme={setTheme}
        lang={lang}
      />
    </div>
  );
};

export default App;

// Converts RGB to Hex
export const rgbToHex = (r: number, g: number, b: number): string => {
  return "#" + ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1);
};

// Converts Hex to RGB
export const hexToRgb = (hex: string) => {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16)
  } : null;
};

interface RGB { r: number; g: number; b: number; }

// Standard Euclidean distance
const euclideanDistance = (rgb1: RGB, rgb2: RGB): number => {
  return Math.sqrt(
    Math.pow(rgb1.r - rgb2.r, 2) + 
    Math.pow(rgb1.g - rgb2.g, 2) + 
    Math.pow(rgb1.b - rgb2.b, 2)
  );
};

const CHROMATIC_BASE_COLORS: { name: string; rgb: RGB }[] = [
  { name: 'red', rgb: { r: 255, g: 0, b: 0 } },
  { name: 'pink', rgb: { r: 255, g: 192, b: 203 } },
  { name: 'orange', rgb: { r: 255, g: 165, b: 0 } },
  { name: 'blue', rgb: { r: 0, g: 0, b: 255 } },
  { name: 'green', rgb: { r: 0, g: 128, b: 0 } },
  { name: 'purple', rgb: { r: 128, g: 0, b: 128 } },
  { name: 'yellow', rgb: { r: 255, g: 255, b: 0 } },
  { name: 'brown', rgb: { r: 165, g: 42, b: 42 } },
  { name: 'magenta', rgb: { r: 255, g: 0, b: 255 } },
  { name: 'cyan', rgb: { r: 0, g: 255, b: 255 } },
];

/**
 * Reduces the grid colors by categorizing pixels into base colors
 * and replacing them with the average color of that category.
 */
export const reduceGridToAverageColors = (grid: string[][]): string[][] => {
  const newGrid = grid.map(row => [...row]);
  const rows = newGrid.length;
  if (rows === 0) return newGrid;
  const cols = newGrid[0].length;

  // Prepare buckets for aggregation
  // Keys: 'black', 'white', 'grey', and names from CHROMATIC_BASE_COLORS
  const buckets: Record<string, { sumR: number; sumG: number; sumB: number; count: number; pixels: { r: number; c: number }[] }> = {};

  const initBucket = (key: string) => {
    if (!buckets[key]) {
      buckets[key] = { sumR: 0, sumG: 0, sumB: 0, count: 0, pixels: [] };
    }
  };

  // 1. Categorize pixels
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const color = newGrid[r][c];
      if (color === 'transparent') continue;

      const rgb = hexToRgb(color);
      if (!rgb) continue;

      let category = '';

      const { r: R, g: G, b: B } = rgb;
      const maxVal = Math.max(R, G, B);
      const minVal = Math.min(R, G, B);

      // Logic Step 1: Check Black
      if (R < 40 && G < 40 && B < 40) {
        category = 'black';
      } 
      // Logic Step 2: Check White
      else if (R > 240 && G > 240 && B > 240) {
        category = 'white';
      } 
      // Logic Step 3: Check Grey
      else if ((maxVal - minVal) <= 10) {
        category = 'grey';
      } 
      // Logic Step 4: Euclidean distance to chromatic colors
      else {
        let minDist = Infinity;
        let bestMatch = 'red'; // Default fallback

        for (const base of CHROMATIC_BASE_COLORS) {
          const dist = euclideanDistance(rgb, base.rgb);
          if (dist < minDist) {
            minDist = dist;
            bestMatch = base.name;
          }
        }
        category = bestMatch;
      }

      initBucket(category);
      buckets[category].pixels.push({ r, c });
      buckets[category].sumR += R;
      buckets[category].sumG += G;
      buckets[category].sumB += B;
      buckets[category].count++;
    }
  }

  // 2. Calculate average and replace
  Object.keys(buckets).forEach(key => {
    const bucket = buckets[key];
    if (bucket.count > 0) {
      const avgR = Math.round(bucket.sumR / bucket.count);
      const avgG = Math.round(bucket.sumG / bucket.count);
      const avgB = Math.round(bucket.sumB / bucket.count);
      const avgHex = rgbToHex(avgR, avgG, avgB);

      bucket.pixels.forEach(p => {
        newGrid[p.r][p.c] = avgHex;
      });
    }
  });

  return newGrid;
};

import React, { useRef, useState, useEffect } from 'react';
import { 
  Pencil, 
  Eraser, 
  Pipette, 
  Trash2, 
  Download, 
  Grid3X3, 
  Image as ImageIcon,
  Square,
  Circle,
  Clock,
  ChevronDown,
  ChevronUp,
  Palette
} from 'lucide-react';
import { ToolType, PRESETS, BoardStyle, Language, Theme } from '../types';
import { translations } from '../utils/translations';

interface ToolbarProps {
  tool: ToolType;
  setTool: (t: ToolType) => void;
  activeColor: string;
  setActiveColor: (c: string) => void;
  gridSize: number;
  setGridSize: (s: number) => void;
  onClear: () => void;
  onDownload: () => void;
  onUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onSimplifyColors: () => void;
  showGridLines: boolean;
  setShowGridLines: (v: boolean) => void;
  boardStyle: BoardStyle;
  setBoardStyle: (s: BoardStyle) => void;
  beadSize: number;
  setBeadSize: (s: number) => void;
  lang: Language;
  theme: Theme;
}

const Toolbar: React.FC<ToolbarProps> = ({
  tool, setTool,
  activeColor, setActiveColor,
  gridSize, setGridSize,
  onClear,
  onDownload,
  onUpload,
  onSimplifyColors,
  showGridLines, setShowGridLines,
  boardStyle, setBoardStyle,
  beadSize, setBeadSize,
  lang,
  theme
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isDark = theme === 'dark';

  // Local state for the custom input to allow typing
  const [customSize, setCustomSize] = useState<string>(gridSize.toString());

  // Recent Colors State
  const [recentColors, setRecentColors] = useState<string[]>([]);
  const [showRecent, setShowRecent] = useState<boolean>(true);

  const t = translations[lang];

  // Sync local input when external grid size changes
  useEffect(() => {
    setCustomSize(gridSize.toString());
  }, [gridSize]);

  // Track active color usage for history
  useEffect(() => {
    if (!activeColor || activeColor === 'transparent') return;

    const handler = setTimeout(() => {
      setRecentColors(prev => {
        // If the color is already the most recent, do nothing
        if (prev[0] === activeColor) return prev;
        // Otherwise, move it to front or add it
        const filtered = prev.filter(c => c !== activeColor);
        return [activeColor, ...filtered].slice(0, 12); // Limit to 12 colors
      });
    }, 500); // Debounce to capture final color after picking

    return () => clearTimeout(handler);
  }, [activeColor]);

  const handleCustomSizeCommit = () => {
    let val = parseInt(customSize, 10);

    if (isNaN(val)) {
      setCustomSize(gridSize.toString());
      return;
    }

    // Enforce limits 4 - 40
    if (val < 4) val = 4;
    if (val > 40) val = 40;

    setCustomSize(val.toString());
    if (val !== gridSize) {
      setGridSize(val);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleCustomSizeCommit();
      (e.target as HTMLInputElement).blur();
    }
  };

  const colors = [
    '#000000', '#1a1c2c', '#5d275d', '#b13e53', '#ef7d57',
    '#ffcd75', '#a7f070', '#38b764', '#257179', '#29366f',
    '#3b5dc9', '#41a6f6', '#73eff7', '#f4f4f4', '#94b0c2',
    '#566c86', '#333c57'
  ];

  const handleFileClick = () => {
    fileInputRef.current?.click();
  };

  // Styles based on theme
  const containerClass = isDark 
    ? 'bg-slate-800/50 border-slate-700 text-slate-100' 
    : 'bg-white/80 border-slate-200 text-slate-800 shadow-slate-200';

  const labelClass = isDark ? 'text-slate-400' : 'text-slate-500';

  const inputContainerClass = isDark 
    ? 'bg-slate-900/50 border-slate-700/50' 
    : 'bg-slate-100 border-slate-200';

  const inputTextClass = isDark ? 'text-white' : 'text-slate-800';

  const btnBaseClass = isDark 
    ? 'bg-slate-700 text-slate-400 border-slate-600 hover:bg-slate-600 hover:text-slate-200' 
    : 'bg-slate-100 text-slate-500 border-slate-200 hover:bg-slate-200 hover:text-slate-800';

  const btnActiveClass = isDark 
    ? 'bg-blue-600 border-blue-500 text-white shadow-lg shadow-blue-500/20' 
    : 'bg-blue-500 border-blue-400 text-white shadow-lg shadow-blue-500/20';

  return (
    <div className={`flex flex-col gap-6 p-5 backdrop-blur-xl border rounded-2xl shadow-xl w-full max-w-xs h-fit overflow-y-auto max-h-[90vh] transition-colors duration-300 ${containerClass}`}>

      {/* --- Size Selector --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>
          {t.size_label}
        </label>
        <div className="flex flex-col gap-3">
          <div className="flex flex-wrap gap-2">
            {PRESETS.map(size => (
              <button
                key={size}
                type="button"
                onClick={() => setGridSize(size)}
                className={`
                  flex-1 px-3 py-1.5 text-sm font-medium rounded-md border transition-all
                  ${gridSize === size ? btnActiveClass : btnBaseClass}
                `}
              >
                {size}
              </button>
            ))}
          </div>

          {/* Custom Input */}
          <div className={`flex items-center gap-2 p-2 rounded-lg border ${inputContainerClass}`}>
             <span className={`text-xs font-medium whitespace-nowrap px-1 ${labelClass}`}>{t.custom_size}:</span>
             <input 
                type="number"
                min={4}
                max={40}
                value={customSize}
                onChange={(e) => setCustomSize(e.target.value)}
                onBlur={handleCustomSizeCommit}
                onKeyDown={handleKeyDown}
                className={`w-full bg-transparent text-sm text-right focus:outline-none placeholder-slate-400 ${inputTextClass}`}
                placeholder="4-40"
             />
             <span className="text-xs text-slate-400 pr-1">px</span>
          </div>
        </div>
      </div>

      {/* --- Board Style --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>{t.board_style}</label>
        <div className="grid grid-cols-2 gap-2">
           <ToolButton 
             active={boardStyle === BoardStyle.SQUARE}
             onClick={() => setBoardStyle(BoardStyle.SQUARE)}
             icon={<Square size={18} />}
             label={t.style_square}
             theme={theme}
           />
           <ToolButton 
             active={boardStyle === BoardStyle.BEAD}
             onClick={() => setBoardStyle(BoardStyle.BEAD)}
             icon={<Circle size={18} />}
             label={t.style_bead}
             theme={theme}
           />
        </div>

        {/* Bead Size Slider - Only visible in Bead mode */}
        {boardStyle === BoardStyle.BEAD && (
            <div className={`mt-3 p-2 rounded-lg border animate-in fade-in slide-in-from-top-2 duration-200 ${isDark ? 'bg-slate-900/30 border-slate-700/30' : 'bg-slate-50 border-slate-200'}`}>
                <div className="flex justify-between items-center mb-1">
                    <span className="text-[10px] uppercase font-bold text-slate-500">{t.bead_diameter}</span>
                    <span className={`text-xs font-mono ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>{beadSize}%</span>
                </div>
                <input 
                    type="range" 
                    min="20" 
                    max="100" 
                    step="5"
                    value={beadSize}
                    onChange={(e) => setBeadSize(Number(e.target.value))}
                    className={`w-full h-1.5 rounded-lg appearance-none cursor-pointer accent-blue-500 hover:accent-blue-400 ${isDark ? 'bg-slate-700' : 'bg-slate-300'}`}
                />
            </div>
        )}
      </div>

      {/* --- Tools --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>{t.tools_label}</label>
        <div className="grid grid-cols-4 gap-2">
          <ToolButton 
            active={tool === ToolType.PEN} 
            onClick={() => setTool(ToolType.PEN)} 
            icon={<Pencil size={18} />} 
            label={t.tool_pen}
            theme={theme}
          />
          <ToolButton 
            active={tool === ToolType.ERASER} 
            onClick={() => setTool(ToolType.ERASER)} 
            icon={<Eraser size={18} />} 
            label={t.tool_eraser}
            theme={theme}
          />
          <ToolButton 
            active={tool === ToolType.EYEDROPPER} 
            onClick={() => setTool(ToolType.EYEDROPPER)} 
            icon={<Pipette size={18} />} 
            label={t.tool_pick}
            theme={theme}
          />
          <ToolButton 
            active={showGridLines} 
            onClick={() => setShowGridLines(!showGridLines)} 
            icon={<Grid3X3 size={18} />} 
            label={t.tool_grid}
            theme={theme}
          />
        </div>
      </div>

      {/* --- Colors --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>{t.palette_label}</label>
        <div className="grid grid-cols-6 gap-2 mb-3">
          {colors.map(c => (
            <button
              key={c}
              type="button"
              onClick={() => setActiveColor(c)}
              className={`
                w-8 h-8 rounded-full border-2 transition-transform hover:scale-110
                ${activeColor === c ? 'border-white ring-2 ring-blue-500' : 'border-transparent'}
              `}
              style={{ backgroundColor: c }}
            />
          ))}
        </div>
        <div className={`flex items-center gap-2 p-2 rounded-lg ${isDark ? 'bg-slate-700/50' : 'bg-slate-200/50'}`}>
          <input 
            type="color" 
            value={activeColor}
            onChange={(e) => setActiveColor(e.target.value)}
            className="w-8 h-8 rounded cursor-pointer bg-transparent border-none p-0"
          />
          <span className={`text-xs font-mono uppercase ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>{activeColor}</span>
        </div>
      </div>

      {/* --- Recent Colors --- */}
      {recentColors.length > 0 && (
          <div className={`pt-2 border-t ${isDark ? 'border-slate-700/50' : 'border-slate-200'}`}>
            <button 
                type="button"
                onClick={() => setShowRecent(!showRecent)}
                className={`flex items-center justify-between w-full text-xs font-semibold uppercase tracking-wider mb-2 transition-colors ${isDark ? 'text-slate-400 hover:text-slate-300' : 'text-slate-500 hover:text-slate-700'}`}
            >
                <span className="flex items-center gap-1.5">
                    <Clock size={12} />
                    {t.recent_label}
                </span>
                {showRecent ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
            </button>

            {showRecent && (
                <div className="grid grid-cols-6 gap-2 mb-3 animate-in fade-in slide-in-from-top-1 duration-200">
                {recentColors.map(c => (
                    <button
                    key={c}
                    type="button"
                    onClick={() => setActiveColor(c)}
                    className={`
                        w-8 h-8 rounded-full border-2 transition-transform hover:scale-110 shadow-sm
                        ${activeColor === c ? 'border-white ring-2 ring-blue-500/50' : (isDark ? 'border-slate-600/50' : 'border-slate-300')}
                    `}
                    style={{ backgroundColor: c }}
                    title={c}
                    />
                ))}
                </div>
            )}
          </div>
      )}

      {/* --- Actions --- */}
      <div className={`space-y-3 pt-4 border-t ${isDark ? 'border-slate-700' : 'border-slate-200'}`}>

        <input 
          type="file" 
          ref={fileInputRef}
          onChange={onUpload}
          accept="image/*"
          className="hidden" 
        />

        <ActionButton 
          onClick={handleFileClick} 
          icon={<ImageIcon size={18} />} 
          label={t.upload_image} 
          variant="secondary"
          theme={theme}
        />

        <ActionButton 
          onClick={onSimplifyColors} 
          icon={<Palette size={18} />} 
          label={t.simplify_colors} 
          variant="secondary"
          theme={theme}
        />

        <div className="grid grid-cols-2 gap-2">
            <ActionButton 
                onClick={onClear} 
                icon={<Trash2 size={18} />} 
                label={t.clear} 
                variant="danger"
                theme={theme}
            />
            <ActionButton 
                onClick={onDownload} 
                icon={<Download size={18} />} 
                label={t.save_image} 
                variant="primary"
                theme={theme}
            />
        </div>
      </div>
    </div>
  );
};

// --- Sub-components for styling ---

const ToolButton = ({ active, onClick, icon, label, theme }: any) => {
  const isDark = theme === 'dark';
  return (
    <button
      type="button"
      onClick={onClick}
      title={label}
      className={`
        flex items-center justify-center gap-2 p-3 rounded-xl transition-all
        ${active 
          ? (isDark ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/25' : 'bg-blue-500 text-white shadow-lg shadow-blue-500/25')
          : (isDark ? 'bg-slate-700 text-slate-400 hover:bg-slate-600 hover:text-slate-200' : 'bg-slate-100 text-slate-500 hover:bg-slate-200 hover:text-slate-800')}
      `}
    >
      {icon}
    </button>
  );
};

const ActionButton = ({ onClick, icon, label, variant = 'primary', theme }: any) => {
  const isDark = theme === 'dark';

  const styles = {
    primary: isDark 
        ? 'bg-slate-700 hover:bg-slate-600 text-white border-slate-600'
        : 'bg-slate-800 hover:bg-slate-700 text-white border-slate-800',
    secondary: isDark
        ? 'bg-slate-700/50 hover:bg-slate-700 text-slate-300 border-dashed border-slate-500'
        : 'bg-slate-100 hover:bg-slate-200 text-slate-600 border-dashed border-slate-300',
    danger: isDark
        ? 'bg-red-500/10 hover:bg-red-500/20 text-red-400 border-red-500/30'
        : 'bg-red-50 hover:bg-red-100 text-red-600 border-red-200',
  };

  return (
    <button
      type="button"
      onClick={onClick}
      className={`
        flex items-center justify-center gap-2 w-full py-2.5 px-4 rounded-lg text-sm font-medium border transition-all
        ${styles[variant as keyof typeof styles]}
      `}
    >
      {icon}
      {label}
    </button>
  );
};

export default Toolbar;

import React, { useState, useEffect, useCallback } from 'react';
import { Undo2, Redo2, Languages, Settings as SettingsIcon } from 'lucide-react';
import Grid from './components/Grid';
import Toolbar from './components/Toolbar';
import ClearConfirmationModal from './components/ClearConfirmationModal';
import SettingsModal from './components/SettingsModal';
import { GridData, ToolType, DEFAULT_COLOR, EMPTY_COLOR, BoardStyle, Language, Theme } from './types';
import { processImageToGrid, exportGridToImage } from './utils/imageHelper';
import { reduceGridToAverageColors } from './utils/colorUtils';
import { translations } from './utils/translations';

// Helper to create a fresh grid
const createGrid = (size: number): GridData => {
  return Array(size).fill(null).map(() => Array(size).fill(EMPTY_COLOR));
};

const App: React.FC = () => {
  // Language & Theme State
  const [lang, setLang] = useState<Language>('zh');
  const [theme, setTheme] = useState<Theme>('dark');

  // State
  const [gridSize, setGridSize] = useState<number>(16);
  // Initialize grid immediately with the default size
  const [grid, setGrid] = useState<GridData>(() => createGrid(16));
  const [activeColor, setActiveColor] = useState<string>(DEFAULT_COLOR);
  const [tool, setTool] = useState<ToolType>(ToolType.PEN);
  const [showGridLines, setShowGridLines] = useState<boolean>(true);
  const [boardStyle, setBoardStyle] = useState<BoardStyle>(BoardStyle.SQUARE);
  const [beadSize, setBeadSize] = useState<number>(85); // Percentage 20-100

  // History State
  const [history, setHistory] = useState<GridData[]>([]);
  const [historyIndex, setHistoryIndex] = useState<number>(-1);

  // Modal States
  const [isClearModalOpen, setIsClearModalOpen] = useState(false);
  const [skipClearConfirm, setSkipClearConfirm] = useState(false);
  const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);

  // Get current translations
  const t = translations[lang];
  const isDark = theme === 'dark';

  // Initialize history on first load or reset
  useEffect(() => {
    const initialGrid = createGrid(gridSize);
    setGrid(initialGrid);
    setHistory([initialGrid]);
    setHistoryIndex(0);
  }, [gridSize]); // Reset everything when grid size changes

  // History Helper: Add current grid state to history
  const addToHistory = useCallback((newGridState: GridData) => {
    setHistory(prev => {
      const newHistory = prev.slice(0, historyIndex + 1);
      // Deep copy to ensure history immutability
      const copy = JSON.parse(JSON.stringify(newGridState));
      newHistory.push(copy);
      return newHistory;
    });
    setHistoryIndex(prev => prev + 1);
  }, [historyIndex]);

  // Handle Undo
  const handleUndo = () => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      setHistoryIndex(newIndex);
      setGrid(JSON.parse(JSON.stringify(history[newIndex])));
    }
  };

  // Handle Redo
  const handleRedo = () => {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      setHistoryIndex(newIndex);
      setGrid(JSON.parse(JSON.stringify(history[newIndex])));
    }
  };

  // Handlers
  const handleStrokeEnd = () => {
    addToHistory(grid);
  };

  // Logic to actually perform the clear operation
  const performClear = () => {
    const newGrid = createGrid(gridSize);
    setGrid(newGrid);
    addToHistory(newGrid);
    setIsClearModalOpen(false);
  };

  // Triggered when user clicks "Clear" in toolbar
  const handleClearRequest = () => {
    if (skipClearConfirm) {
        performClear();
    } else {
        setIsClearModalOpen(true);
    }
  };

  // Triggered when user confirms in the modal
  const handleConfirmClear = (dontShowAgain: boolean) => {
    if (dontShowAgain) {
        setSkipClearConfirm(true);
    }
    performClear();
  };

  const handleDownload = () => {
    exportGridToImage(grid);
  };

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const newGrid = await processImageToGrid(file, gridSize, gridSize);
      setGrid(newGrid);
      addToHistory(newGrid);
      // Reset file input
      e.target.value = '';
    } catch (error) {
      console.error("Failed to process image", error);
      alert(t.error_processing_alert);
    }
  };

  const handleSimplifyColors = () => {
    const newGrid = reduceGridToAverageColors(grid);
    setGrid(newGrid);
    addToHistory(newGrid);
  };

  const toggleLanguage = () => {
    setLang(prev => prev === 'zh' ? 'en' : 'zh');
  };

  return (
    <div className={`min-h-screen flex flex-col items-center justify-center p-4 md:p-8 relative overflow-hidden transition-colors duration-500 ${isDark ? 'bg-slate-900 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>

      {/* Background decoration */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0">
         <div className={`absolute top-[-20%] left-[-10%] w-[50%] h-[50%] rounded-full blur-[120px] transition-colors duration-500 ${isDark ? 'bg-blue-600/10' : 'bg-blue-400/20'}`}></div>
