// Converts RGB to Hex
export const rgbToHex = (r: number, g: number, b: number): string => {
  return "#" + ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1);
};

// Converts Hex to RGB
export const hexToRgb = (hex: string) => {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16)
  } : null;
};

interface RGB { r: number; g: number; b: number; }

// Standard Euclidean distance
const euclideanDistance = (rgb1: RGB, rgb2: RGB): number => {
  return Math.sqrt(
    Math.pow(rgb1.r - rgb2.r, 2) + 
    Math.pow(rgb1.g - rgb2.g, 2) + 
    Math.pow(rgb1.b - rgb2.b, 2)
  );
};

const CHROMATIC_BASE_COLORS: { name: string; rgb: RGB }[] = [
  { name: 'red', rgb: { r: 255, g: 0, b: 0 } },
  { name: 'pink', rgb: { r: 255, g: 192, b: 203 } },
  { name: 'orange', rgb: { r: 255, g: 165, b: 0 } },
  { name: 'blue', rgb: { r: 0, g: 0, b: 255 } },
  { name: 'green', rgb: { r: 0, g: 128, b: 0 } },
  { name: 'purple', rgb: { r: 128, g: 0, b: 128 } },
  { name: 'yellow', rgb: { r: 255, g: 255, b: 0 } },
  { name: 'brown', rgb: { r: 165, g: 42, b: 42 } },
  { name: 'magenta', rgb: { r: 255, g: 0, b: 255 } },
  { name: 'cyan', rgb: { r: 0, g: 255, b: 255 } },
];

const FIXED_COLORS = {
    black: '#000000',
    white: '#ffffff',
    grey: '#808080' // Standard mid-grey for the grey category
};

/**
 * Reduces the grid colors by categorizing pixels into base colors
 * and replacing them with the base color itself.
 */
export const reduceGridToAverageColors = (grid: string[][]): string[][] => {
  const newGrid = grid.map(row => [...row]);
  const rows = newGrid.length;
  if (rows === 0) return newGrid;
  const cols = newGrid[0].length;

  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const color = newGrid[r][c];
      if (color === 'transparent') continue;

      const rgb = hexToRgb(color);
      if (!rgb) continue;

      const { r: R, g: G, b: B } = rgb;
      const maxVal = Math.max(R, G, B);
      const minVal = Math.min(R, G, B);

      // Logic Step 1: Check Black (RGB all < 40)
      if (R < 40 && G < 40 && B < 40) {
        newGrid[r][c] = FIXED_COLORS.black;
      } 
      // Logic Step 2: Check White (RGB all > 240)
      else if (R > 240 && G > 240 && B > 240) {
        newGrid[r][c] = FIXED_COLORS.white;
      } 
      // Logic Step 3: Check Grey (Difference between max and min <= 10)
      else if ((maxVal - minVal) <= 10) {
        newGrid[r][c] = FIXED_COLORS.grey;
      } 
      // Logic Step 4: Euclidean distance to chromatic colors
      else {
        let minDist = Infinity;
        let bestMatchRgb = CHROMATIC_BASE_COLORS[0].rgb; // Default fallback

        for (const base of CHROMATIC_BASE_COLORS) {
          const dist = euclideanDistance(rgb, base.rgb);
          if (dist < minDist) {
            minDist = dist;
            bestMatchRgb = base.rgb;
          }
        }
        newGrid[r][c] = rgbToHex(bestMatchRgb.r, bestMatchRgb.g, bestMatchRgb.b);
      }
    }
  }

  return newGrid;
};

import { COLOR_CSV_DATA } from './colorData';

// Converts RGB to Hex
export const rgbToHex = (r: number, g: number, b: number): string => {
  return "#" + ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1);
};

// Converts Hex to RGB
export const hexToRgb = (hex: string) => {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16)
  } : null;
};

interface RGB { r: number; g: number; b: number; }

// Reference point structure derived from CSV
interface ColorReference {
  r: number;
  g: number;
  b: number;
  labelId: string;
}

// Parse CSV content into usable reference points
const parseReferencePoints = (csv: string): ColorReference[] => {
  const lines = csv.trim().split('\n');
  const refs: ColorReference[] = [];
  // Determine start index based on header presence
  const startIndex = lines[0].startsWith('R,G,B') ? 1 : 0;

  for (let i = startIndex; i < lines.length; i++) {
    const parts = lines[i].split(',');
    if (parts.length < 6) continue;

    const r = parseInt(parts[0], 10);
    const g = parseInt(parts[1], 10);
    const b = parseInt(parts[2], 10);
    // Label ID is at index 5
    const labelId = parts[5].trim();

    if (!isNaN(r)) {
        refs.push({ r, g, b, labelId });
    }
  }
  return refs;
};

// Load reference points into memory immediately
const REFERENCE_POINTS = parseReferencePoints(COLOR_CSV_DATA);

// Standard Base Colors Palette mapped from Label IDs
const BASE_PALETTE: Record<string, string> = {
  black: '#000000',
  white: '#ffffff',
  gray: '#808080',
  grey: '#808080', // Fallback
  red: '#FF0000',
  pink: '#FFC0CB',
  orange: '#FFA500',
  blue: '#0000FF',
  green: '#008000',
  purple: '#800080',
  yellow: '#FFFF00',
  brown: '#8B4513',
  magenta: '#FF00FF',
  cyan: '#00FFFF',
};

/**
 * Reduces the grid colors by matching each pixel to the nearest neighbor
 * found in the provided CSV dataset and mapping it to the defined base palette.
 */
export const reduceGridToAverageColors = (grid: string[][]): string[][] => {
  const newGrid = grid.map(row => [...row]);
  const rows = newGrid.length;
  if (rows === 0) return newGrid;
  const cols = newGrid[0].length;

  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const color = newGrid[r][c];
      if (color === 'transparent') continue;

      const rgb = hexToRgb(color);
      if (!rgb) continue;

      const { r: R, g: G, b: B } = rgb;

      let minDist = Infinity;
      let bestLabel = 'black'; // Default fallback

      // Iterate through all reference points from CSV to find the nearest match
      for (const ref of REFERENCE_POINTS) {
        // Squared Euclidean distance is sufficient for comparison (avoids sqrt)
        const distSq = (R - ref.r) ** 2 + (G - ref.g) ** 2 + (B - ref.b) ** 2;

        if (distSq < minDist) {
          minDist = distSq;
          bestLabel = ref.labelId;
        }
      }

      // Update pixel to the canonical base color for that label
      const matchedColor = BASE_PALETTE[bestLabel];
      if (matchedColor) {
          newGrid[r][c] = matchedColor;
      }
    }
  }

  return newGrid;
};

