    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const newGrid = await processImageToGrid(file, gridSize, gridSize);
      setGrid(newGrid);
      addToHistory(newGrid);
      // Reset file input
      e.target.value = '';
