          <div className="flex flex-wrap gap-2">
            {PRESETS.map(size => (
              <button
                key={size}
                type="button"
                onClick={() => setGridSize(size)}
                className={`
                  flex-1 px-3 py-1.5 text-sm font-medium rounded-md border transition-all
                  ${gridSize === size ? btnActiveClass : btnBaseClass}
                `}
