                            ${isSelected ? 'scale-110 ring-2 ring-offset-2 ring-blue-500 ring-offset-slate-800' : 'opacity-60 hover:opacity-100 scale-90'}
                        `}
                        style={{ backgroundColor: color }}
                        title={color}
