import { COLOR_CSV_DATA } from './colorData';

// Converts RGB to Hex
export const rgbToHex = (r: number, g: number, b: number): string => {
  return "#" + ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1);
};

// Converts Hex to RGB
export const hexToRgb = (hex: string) => {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16)
  } : null;
};

interface RGB { r: number; g: number; b: number; }

// Reference point structure derived from CSV
interface ColorReference {
  r: number;
  g: number;
  b: number;
  labelId: string;
}

// Parse CSV content into usable reference points
const parseReferencePoints = (csv: string): ColorReference[] => {
  const lines = csv.trim().split('\n');
  const refs: ColorReference[] = [];
  // Determine start index based on header presence
  const startIndex = lines[0].startsWith('R,G,B') ? 1 : 0;

  for (let i = startIndex; i < lines.length; i++) {
    const parts = lines[i].split(',');
    if (parts.length < 6) continue;

    const r = parseInt(parts[0], 10);
    const g = parseInt(parts[1], 10);
    const b = parseInt(parts[2], 10);
    // Label ID is at index 5
    const labelId = parts[5].trim();

    if (!isNaN(r)) {
        refs.push({ r, g, b, labelId });
    }
  }
  return refs;
};

// Load reference points into memory immediately
const REFERENCE_POINTS = parseReferencePoints(COLOR_CSV_DATA);

/**
 * Reduces the grid colors by matching each pixel to the nearest neighbor
 * found in the provided CSV dataset (categorization).
 * 
 * Instead of replacing the pixel with the category's base color,
 * it groups all pixels belonging to the same category, calculates the
 * average RGB of that group, and replaces all pixels in the group with that average.
 */
export const reduceGridToAverageColors = (grid: string[][]): string[][] => {
  const newGrid = grid.map(row => [...row]);
  const rows = newGrid.length;
  if (rows === 0) return newGrid;
  const cols = newGrid[0].length;

  // Store pixels grouped by their nearest reference label (Category)
  // key: labelId, value: Array of pixel data with original RGB and position
  const groups: Record<string, { r: number, g: number, b: number, row: number, col: number }[]> = {};

  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const color = newGrid[r][c];
      if (color === 'transparent') continue;

      const rgb = hexToRgb(color);
      if (!rgb) continue;

      const { r: R, g: G, b: B } = rgb;

      let minDist = Infinity;
      let bestLabel = 'unknown';

      // Find nearest neighbor in CSV reference points
      for (const ref of REFERENCE_POINTS) {
        // Squared Euclidean distance
        const distSq = (R - ref.r) ** 2 + (G - ref.g) ** 2 + (B - ref.b) ** 2;

        if (distSq < minDist) {
          minDist = distSq;
          bestLabel = ref.labelId;
        }
      }

      // Add pixel info to the corresponding group
      if (!groups[bestLabel]) {
        groups[bestLabel] = [];
      }
      groups[bestLabel].push({ r: R, g: G, b: B, row: r, col: c });
    }
  }

  // Calculate average for each group and apply to grid
  Object.keys(groups).forEach(label => {
      const pixels = groups[label];
      if (pixels.length === 0) return;

      // Sum RGB values
      const total = pixels.reduce((acc, p) => ({ 
          r: acc.r + p.r, 
          g: acc.g + p.g, 
          b: acc.b + p.b 
      }), { r: 0, g: 0, b: 0 });

      // Calculate Average
      const avgR = Math.round(total.r / pixels.length);
      const avgG = Math.round(total.g / pixels.length);
      const avgB = Math.round(total.b / pixels.length);

      // Convert back to hex
      const avgHex = rgbToHex(avgR, avgG, avgB);

      // Update all pixels in this group with the average color
      pixels.forEach(p => {
          newGrid[p.row][p.col] = avgHex;
      });
  });

  return newGrid;
};

/**
 * Identifies the top K dominant average colors using K-Means clustering.
 * Filters out clusters that represent less than 1% of the total pixels.
 */
export const getDominantColors = (grid: string[][], k: number = 5): string[] => {
  // 1. Flatten grid and extract all valid RGB values
  const pixels: RGB[] = [];
  grid.forEach(row => {
    row.forEach(color => {
      if (color !== 'transparent') {
        const rgb = hexToRgb(color);
        if (rgb) pixels.push(rgb);
      }
    });
  });

  const totalPixels = pixels.length;
  if (totalPixels === 0) return [];

  // If we have fewer pixels or unique colors than K, just return unique averaged colors.
  if (totalPixels <= k) {
      const unique = Array.from(new Set(pixels.map(p => rgbToHex(p.r, p.g, p.b))));
      return unique;
  }

  // 2. Initialize Centroids (Pick random pixels to start)
  let centroids: RGB[] = [];
  const usedIndices = new Set<number>();
  while (centroids.length < k && centroids.length < totalPixels) {
      const idx = Math.floor(Math.random() * totalPixels);
      if (!usedIndices.has(idx)) {
          centroids.push({ ...pixels[idx] });
          usedIndices.add(idx);
      }
  }

  // 3. K-Means Loop
  const maxIterations = 15;
  let clusters: RGB[][] = Array.from({ length: k }, () => []);

  for (let iter = 0; iter < maxIterations; iter++) {
      // Clear clusters
      clusters = Array.from({ length: k }, () => []);

      // Assign pixels to nearest centroid
      pixels.forEach(p => {
          let minDist = Infinity;
          let clusterIndex = 0;

          centroids.forEach((c, idx) => {
              const dist = (p.r - c.r) ** 2 + (p.g - c.g) ** 2 + (p.b - c.b) ** 2;
              if (dist < minDist) {
                  minDist = dist;
                  clusterIndex = idx;
              }
          });
          clusters[clusterIndex].push(p);
      });

      // Recalculate centroids
      let converged = true;
      clusters.forEach((cluster, idx) => {
          if (cluster.length === 0) return; // Keep old centroid if cluster empty

          const sum = cluster.reduce((acc, p) => ({ r: acc.r + p.r, g: acc.g + p.g, b: acc.b + p.b }), { r: 0, g: 0, b: 0 });
          const newR = sum.r / cluster.length;
          const newG = sum.g / cluster.length;
          const newB = sum.b / cluster.length;

          // Check for convergence
          if (Math.abs(newR - centroids[idx].r) > 1 || 
              Math.abs(newG - centroids[idx].g) > 1 || 
              Math.abs(newB - centroids[idx].b) > 1) {
              converged = false;
          }

          centroids[idx] = { r: newR, g: newG, b: newB };
      });

      if (converged) break;
  }

  // 4. Sort clusters by size (largest first)
  const sortedClusters = clusters
      .filter(c => c.length > 0)
      .sort((a, b) => b.length - a.length);

  // 5. Filter out insignificant clusters (< 1% of total pixels)
  // This prevents showing noise as a dominant color
  const threshold = Math.ceil(totalPixels * 0.01);
  const significantClusters = sortedClusters.filter(c => c.length >= threshold);

  // 6. Calculate average color for the top K clusters
  const dominantHexColors = significantClusters.slice(0, k).map(cluster => {
      const sum = cluster.reduce((acc, p) => ({ r: acc.r + p.r, g: acc.g + p.g, b: acc.b + p.b }), { r: 0, g: 0, b: 0 });
      const avgR = Math.round(sum.r / cluster.length);
      const avgG = Math.round(sum.g / cluster.length);
      const avgB = Math.round(sum.b / cluster.length);
      return rgbToHex(avgR, avgG, avgB);
  });

  return dominantHexColors;
};

/**
 * Replaces every pixel in the grid with the nearest color from the provided palette.
 */
export const applyPaletteToGrid = (grid: string[][], palette: string[]): string[][] => {
  // If no palette provided, return original
  if (!palette || palette.length === 0) return grid;

  // Cache palette RGB values for performance
  const paletteRgb = palette.map(hex => {
      const rgb = hexToRgb(hex);
      return rgb ? { ...rgb, hex } : null;
  }).filter(item => item !== null) as {r: number, g: number, b: number, hex: string}[];

  if (paletteRgb.length === 0) return grid;

  const newGrid = grid.map(row => [...row]);
  const rows = newGrid.length;
  if (rows === 0) return newGrid;
  const cols = newGrid[0].length;

  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const color = newGrid[r][c];
      if (color === 'transparent') continue;

      // Optimization: if the color is already in the palette, skip
      if (palette.includes(color)) continue;

      const currentRgb = hexToRgb(color);
      if (!currentRgb) continue;

      let minDist = Infinity;
      let nearestHex = color;

      for (const p of paletteRgb) {
        // Squared Euclidean distance
        const distSq = (currentRgb.r - p.r) ** 2 + 
                       (currentRgb.g - p.g) ** 2 + 
                       (currentRgb.b - p.b) ** 2;

        if (distSq < minDist) {
          minDist = distSq;
          nearestHex = p.hex;
        }
      }
      newGrid[r][c] = nearestHex;
    }
  }

  return newGrid;
};

import React, { useRef, useState, useEffect } from 'react';
import { 
  Pencil, 
  Eraser, 
  Pipette, 
  Trash2, 
  Download, 
  Grid3X3, 
  Image as ImageIcon,
  Square,
  Circle,
  Clock,
  ChevronDown,
  ChevronUp,
  Palette
} from 'lucide-react';
import { ToolType, PRESETS, BoardStyle, Language, Theme } from '../types';
import { translations } from '../utils/translations';

interface ToolbarProps {
  tool: ToolType;
  setTool: (t: ToolType) => void;
  activeColor: string;
  setActiveColor: (c: string) => void;
  gridSize: number;
  setGridSize: (s: number) => void;
  onClear: () => void;
  onDownload: () => void;
  onUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onIdentifyColors: () => void;
  showGridLines: boolean;
  setShowGridLines: (v: boolean) => void;
  boardStyle: BoardStyle;
  setBoardStyle: (s: BoardStyle) => void;
  beadSize: number;
  setBeadSize: (s: number) => void;
  lang: Language;
  theme: Theme;
}

const Toolbar: React.FC<ToolbarProps> = ({
  tool, setTool,
  activeColor, setActiveColor,
  gridSize, setGridSize,
  onClear,
  onDownload,
  onUpload,
  onIdentifyColors,
  showGridLines, setShowGridLines,
  boardStyle, setBoardStyle,
  beadSize, setBeadSize,
  lang,
  theme
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isDark = theme === 'dark';

  // Local state for the custom input to allow typing
  const [customSize, setCustomSize] = useState<string>(gridSize.toString());

  // Recent Colors State
  const [recentColors, setRecentColors] = useState<string[]>([]);
  const [showRecent, setShowRecent] = useState<boolean>(true);

  const t = translations[lang];

  // Sync local input when external grid size changes
  useEffect(() => {
    setCustomSize(gridSize.toString());
  }, [gridSize]);

  // Track active color usage for history
  useEffect(() => {
    if (!activeColor || activeColor === 'transparent') return;

    const handler = setTimeout(() => {
      setRecentColors(prev => {
        // If the color is already the most recent, do nothing
        if (prev[0] === activeColor) return prev;
        // Otherwise, move it to front or add it
        const filtered = prev.filter(c => c !== activeColor);
        return [activeColor, ...filtered].slice(0, 12); // Limit to 12 colors
      });
    }, 500); // Debounce to capture final color after picking

    return () => clearTimeout(handler);
  }, [activeColor]);

  const handleCustomSizeCommit = () => {
    let val = parseInt(customSize, 10);

    if (isNaN(val)) {
      setCustomSize(gridSize.toString());
      return;
    }

    // Enforce limits 8 - 100
    if (val < 8) val = 8;
    if (val > 100) val = 100;

    setCustomSize(val.toString());
    if (val !== gridSize) {
      setGridSize(val);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleCustomSizeCommit();
      (e.target as HTMLInputElement).blur();
    }
  };

  const colors = [
    '#000000', '#1a1c2c', '#5d275d', '#b13e53', '#ef7d57',
    '#ffcd75', '#a7f070', '#38b764', '#257179', '#29366f',
    '#3b5dc9', '#41a6f6', '#73eff7', '#f4f4f4', '#94b0c2',
    '#566c86', '#333c57'
  ];

  const handleFileClick = () => {
    fileInputRef.current?.click();
  };

  // Styles based on theme
  const containerClass = isDark 
    ? 'bg-slate-800/50 border-slate-700 text-slate-100' 
    : 'bg-white/80 border-slate-200 text-slate-800 shadow-slate-200';

  const labelClass = isDark ? 'text-slate-400' : 'text-slate-500';

  const inputContainerClass = isDark 
    ? 'bg-slate-900/50 border-slate-700/50' 
    : 'bg-slate-100 border-slate-200';

  const inputTextClass = isDark ? 'text-white' : 'text-slate-800';

  const btnBaseClass = isDark 
    ? 'bg-slate-700 text-slate-400 border-slate-600 hover:bg-slate-600 hover:text-slate-200' 
    : 'bg-slate-100 text-slate-500 border-slate-200 hover:bg-slate-200 hover:text-slate-800';

  const btnActiveClass = isDark 
    ? 'bg-blue-600 border-blue-500 text-white shadow-lg shadow-blue-500/20' 
    : 'bg-blue-500 border-blue-400 text-white shadow-lg shadow-blue-500/20';

  return (
    <div className={`flex flex-col gap-6 p-5 backdrop-blur-xl border rounded-2xl shadow-xl w-full max-w-xs h-fit overflow-y-auto max-h-[90vh] transition-colors duration-300 ${containerClass}`}>

      {/* --- Size Selector --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>
          {t.size_label}
        </label>
        <div className="flex flex-col gap-3">
          <div className="flex flex-wrap gap-2">
            {PRESETS.map(size => (
              <button
                key={size}
                type="button"
                onClick={() => setGridSize(size)}
                className={`
                  flex-1 px-3 py-1.5 text-sm font-medium rounded-md border transition-all
                  ${gridSize === size ? btnActiveClass : btnBaseClass}
                `}
              >
                {size}
              </button>
            ))}
          </div>

          {/* Custom Input */}
          <div className={`flex items-center gap-2 p-2 rounded-lg border ${inputContainerClass}`}>
             <span className={`text-xs font-medium whitespace-nowrap px-1 ${labelClass}`}>{t.custom_size}:</span>
             <input 
                type="number"
                min={8}
                max={100}
                value={customSize}
                onChange={(e) => setCustomSize(e.target.value)}
                onBlur={handleCustomSizeCommit}
                onKeyDown={handleKeyDown}
                className={`w-full bg-transparent text-sm text-right focus:outline-none placeholder-slate-400 ${inputTextClass}`}
                placeholder="8-100"
             />
             <span className="text-xs text-slate-400 pr-1">px</span>
          </div>
        </div>
      </div>

      {/* --- Board Style --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>{t.board_style}</label>
        <div className="grid grid-cols-2 gap-2">
           <ToolButton 
             active={boardStyle === BoardStyle.SQUARE}
             onClick={() => setBoardStyle(BoardStyle.SQUARE)}
             icon={<Square size={18} />}
             label={t.style_square}
             theme={theme}
           />
           <ToolButton 
             active={boardStyle === BoardStyle.BEAD}
             onClick={() => setBoardStyle(BoardStyle.BEAD)}
             icon={<Circle size={18} />}
             label={t.style_bead}
             theme={theme}
           />
        </div>

        {/* Bead Size Slider - Only visible in Bead mode */}
        {boardStyle === BoardStyle.BEAD && (
            <div className={`mt-3 p-2 rounded-lg border animate-in fade-in slide-in-from-top-2 duration-200 ${isDark ? 'bg-slate-900/30 border-slate-700/30' : 'bg-slate-50 border-slate-200'}`}>
                <div className="flex justify-between items-center mb-1">
                    <span className="text-[10px] uppercase font-bold text-slate-500">{t.bead_diameter}</span>
                    <span className={`text-xs font-mono ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>{beadSize}%</span>
                </div>
                <input 
                    type="range" 
                    min="20" 
                    max="100" 
                    step="5"
                    value={beadSize}
                    onChange={(e) => setBeadSize(Number(e.target.value))}
                    className={`w-full h-1.5 rounded-lg appearance-none cursor-pointer accent-blue-500 hover:accent-blue-400 ${isDark ? 'bg-slate-700' : 'bg-slate-300'}`}
                />
            </div>
        )}
      </div>

      {/* --- Tools --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>{t.tools_label}</label>
        <div className="grid grid-cols-4 gap-2">
          <ToolButton 
            active={tool === ToolType.PEN} 
            onClick={() => setTool(ToolType.PEN)} 
            icon={<Pencil size={18} />} 
            label={t.tool_pen}
            theme={theme}
          />
          <ToolButton 
            active={tool === ToolType.ERASER} 
            onClick={() => setTool(ToolType.ERASER)} 
            icon={<Eraser size={18} />} 
            label={t.tool_eraser}
            theme={theme}
          />
          <ToolButton 
            active={tool === ToolType.EYEDROPPER} 
            onClick={() => setTool(ToolType.EYEDROPPER)} 
            icon={<Pipette size={18} />} 
            label={t.tool_pick}
            theme={theme}
          />
          <ToolButton 
            active={showGridLines} 
            onClick={() => setShowGridLines(!showGridLines)} 
            icon={<Grid3X3 size={18} />} 
            label={t.tool_grid}
            theme={theme}
          />
        </div>
      </div>

      {/* --- Colors --- */}
      <div>
        <label className={`text-xs font-semibold uppercase tracking-wider mb-2 block ${labelClass}`}>{t.palette_label}</label>
        <div className="grid grid-cols-6 gap-2 mb-3">
          {colors.map(c => (
            <button
              key={c}
              type="button"
              onClick={() => setActiveColor(c)}
              className={`
                w-8 h-8 rounded-full border-2 transition-transform hover:scale-110
                ${activeColor === c ? 'border-white ring-2 ring-blue-500' : 'border-transparent'}
              `}
              style={{ backgroundColor: c }}
            />
          ))}
        </div>
        <div className={`flex items-center gap-2 p-2 rounded-lg ${isDark ? 'bg-slate-700/50' : 'bg-slate-200/50'}`}>
          <input 
            type="color" 
            value={activeColor}
            onChange={(e) => setActiveColor(e.target.value)}
            className="w-8 h-8 rounded cursor-pointer bg-transparent border-none p-0"
          />
          <span className={`text-xs font-mono uppercase ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>{activeColor}</span>
        </div>
      </div>

      {/* --- Recent Colors --- */}
      {recentColors.length > 0 && (
          <div className={`pt-2 border-t ${isDark ? 'border-slate-700/50' : 'border-slate-200'}`}>
            <button 
                type="button"
                onClick={() => setShowRecent(!showRecent)}
                className={`flex items-center justify-between w-full text-xs font-semibold uppercase tracking-wider mb-2 transition-colors ${isDark ? 'text-slate-400 hover:text-slate-300' : 'text-slate-500 hover:text-slate-700'}`}
            >
                <span className="flex items-center gap-1.5">
                    <Clock size={12} />
                    {t.recent_label}
                </span>
                {showRecent ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
            </button>

            {showRecent && (
                <div className="grid grid-cols-6 gap-2 mb-3 animate-in fade-in slide-in-from-top-1 duration-200">
                {recentColors.map(c => (
                    <button
                    key={c}
                    type="button"
                    onClick={() => setActiveColor(c)}
                    className={`
                        w-8 h-8 rounded-full border-2 transition-transform hover:scale-110 shadow-sm
                        ${activeColor === c ? 'border-white ring-2 ring-blue-500/50' : (isDark ? 'border-slate-600/50' : 'border-slate-300')}
                    `}
                    style={{ backgroundColor: c }}
                    title={c}
                    />
                ))}
                </div>
            )}
          </div>
      )}

      {/* --- Actions --- */}
      <div className={`space-y-3 pt-4 border-t ${isDark ? 'border-slate-700' : 'border-slate-200'}`}>

        <input 
          type="file" 
          ref={fileInputRef}
          onChange={onUpload}
          accept="image/*"
          className="hidden" 
        />

        {/* Row 1: Upload + Identify */}
        <div className="grid grid-cols-2 gap-2">
            <ActionButton 
                onClick={handleFileClick} 
                icon={<ImageIcon size={18} />} 
                label={t.upload_image} 
                variant="secondary"
                theme={theme}
            />
            <ActionButton 
                onClick={onIdentifyColors} 
                icon={<Palette size={18} />} 
                label={t.identify_colors} 
                variant="secondary"
                theme={theme}
            />
        </div>

        {/* Row 2: Clear + Save */}
        <div className="grid grid-cols-2 gap-2">
            <ActionButton 
                onClick={onClear} 
                icon={<Trash2 size={18} />} 
                label={t.clear} 
                variant="danger"
                theme={theme}
            />
            <ActionButton 
                onClick={onDownload} 
                icon={<Download size={18} />} 
                label={t.save_image} 
                variant="primary"
                theme={theme}
            />
        </div>
      </div>
    </div>
  );
};

