import React, { useRef, useEffect, useCallback } from 'react';
import { GridData, ToolType, EMPTY_COLOR, BoardStyle, Language, Theme } from '../types';
import { translations } from '../utils/translations';

interface GridProps {
  grid: GridData;
  setGrid: React.Dispatch<React.SetStateAction<GridData>>;
  activeColor: string;
  setActiveColor: (c: string) => void;
  tool: ToolType;
  showGridLines: boolean;
  boardStyle: BoardStyle;
  beadSize: number;
  onStrokeEnd?: () => void;
  lang: Language;
  theme: Theme;
}

// --- Cell Component (Memoized) ---
interface CellProps {
  rIndex: number;
  cIndex: number;
  color: string;
  showGridLines: boolean;
  boardStyle: BoardStyle;
  beadSize: number;
  isDark: boolean;
  onMouseDown: (r: number, c: number) => void;
  onMouseEnter: (r: number, c: number) => void;
}

const Cell = React.memo(({ 
  rIndex, 
  cIndex, 
  color, 
  showGridLines, 
  boardStyle, 
  beadSize, 
  isDark,
  onMouseDown,
  onMouseEnter
}: CellProps) => {
  const isTransparent = color === 'transparent' || color === EMPTY_COLOR;
  const isBead = boardStyle === BoardStyle.BEAD;

  const gridLineClass = isDark ? 'border-slate-700/50' : 'border-slate-200';
  const emptyPegClass = isDark ? 'bg-slate-700 shadow-inner' : 'bg-slate-200 shadow-inner';
  const bgPatternColor = isDark ? '#1e293b' : '#e2e8f0';

  return (
    <div
      onMouseDown={() => onMouseDown(rIndex, cIndex)}
      onMouseEnter={() => onMouseEnter(rIndex, cIndex)}
      className={`
        w-full h-full cursor-crosshair flex items-center justify-center
        ${showGridLines && !isBead ? `border-[0.5px] ${gridLineClass}` : ''}
      `}
      // Prevent browser drag behavior on images/divs which can interfere with painting
      onDragStart={(e) => e.preventDefault()} 
    >
        <div 
           className={`
              transition-all duration-200 pointer-events-none
              ${isBead 
                  ? isTransparent 
                      ? `w-[20%] h-[20%] rounded-full ${emptyPegClass}` // Peg for empty bead
                      : 'rounded-full shadow-md ring-1 ring-black/10' // Filled Bead
                  : 'w-full h-full' // Square
              }
           `}
           style={{ 
              // Size logic: If Square, 100%. If Bead, use dynamic size unless it's an empty peg
              width: isBead ? (isTransparent ? undefined : `${beadSize}%`) : undefined,
              height: isBead ? (isTransparent ? undefined : `${beadSize}%`) : undefined,

              backgroundColor: isBead && isTransparent ? undefined : (color === 'transparent' ? undefined : color),
              backgroundImage: (!isBead && isTransparent)
                ? `linear-gradient(45deg, ${bgPatternColor} 25%, transparent 25%), linear-gradient(-45deg, ${bgPatternColor} 25%, transparent 25%), linear-gradient(45deg, transparent 75%, ${bgPatternColor} 75%), linear-gradient(-45deg, transparent 75%, ${bgPatternColor} 75%)` 
                : 'none',
              backgroundSize: !isBead ? '10px 10px' : undefined,
              backgroundPosition: !isBead ? '0 0, 0 5px, 5px -5px, -5px 0px' : undefined,
              // Add nice 3D lighting effect for colored beads
              boxShadow: (isBead && !isTransparent) 
                ? 'inset -2px -2px 4px rgba(0,0,0,0.3), inset 2px 2px 4px rgba(255,255,255,0.25), 1px 1px 2px rgba(0,0,0,0.5)' 
                : undefined
           }}
        />
    </div>
  );
}, (prev, next) => {
  // Custom comparison function for React.memo
  // Only re-render if visual properties change
  return (
    prev.color === next.color &&
    prev.showGridLines === next.showGridLines &&
    prev.boardStyle === next.boardStyle &&
    prev.beadSize === next.beadSize &&
    prev.isDark === next.isDark
  );
});

// --- Main Grid Component ---

const Grid: React.FC<GridProps> = ({ 
  grid, 
  setGrid, 
  activeColor, 
  setActiveColor,
  tool, 
  showGridLines,
  boardStyle,
  beadSize,
  onStrokeEnd,
  lang,
  theme
}) => {
  const isDrawing = useRef(false);
  const t = translations[lang];
  const isDark = theme === 'dark';

  // Refs for current tool state to be accessible in callbacks without re-creating functions
  const toolRef = useRef(tool);
  const activeColorRef = useRef(activeColor);
  const gridRef = useRef(grid);

  useEffect(() => { toolRef.current = tool; }, [tool]);
  useEffect(() => { activeColorRef.current = activeColor; }, [activeColor]);
  useEffect(() => { gridRef.current = grid; }, [grid]);

  // Safety check
  if (!grid || grid.length === 0 || !grid[0]) {
    return (
        <div className={`flex items-center justify-center w-64 h-64 ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>
            {t.loading}
        </div>
    );
  }

  // Helper to paint a specific cell
  const paintCell = useCallback((rowIndex: number, colIndex: number) => {
    // Access current state via refs to avoid closure staleness without dependency updates
    const currentGrid = gridRef.current;
    if (rowIndex < 0 || rowIndex >= currentGrid.length || colIndex < 0 || colIndex >= currentGrid[0].length) return;

    const currentColor = currentGrid[rowIndex][colIndex];
    let targetColor = activeColorRef.current;
    const currentTool = toolRef.current;

    if (currentTool === ToolType.ERASER) {
      targetColor = EMPTY_COLOR;
    } else if (currentTool === ToolType.EYEDROPPER) {
        if (currentColor !== EMPTY_COLOR) {
            setActiveColor(currentColor);
        }
        return; // Don't paint
    }

    if (currentColor === targetColor) return;

    setGrid(prev => {
      const newGrid = [...prev]; // Shallow copy outer
      newGrid[rowIndex] = [...prev[rowIndex]]; // Copy row
      newGrid[rowIndex][colIndex] = targetColor;
      return newGrid;
    });
  }, [setGrid, setActiveColor]); // Stable dependencies

  const handleMouseDown = useCallback((r: number, c: number) => {
    isDrawing.current = true;
    paintCell(r, c);
  }, [paintCell]);

  const handleMouseEnter = useCallback((r: number, c: number) => {
    if (isDrawing.current) {
      paintCell(r, c);
    }
  }, [paintCell]);

  const handleMouseUp = useCallback(() => {
    if (isDrawing.current) {
      isDrawing.current = false;
      if (onStrokeEnd) onStrokeEnd();
    }
  }, [onStrokeEnd]);

  // Global mouse up to catch drags that go outside
  useEffect(() => {
    const handleGlobalMouseUp = () => { 
        if (isDrawing.current) {
            handleMouseUp();
        }
    };
    window.addEventListener('mouseup', handleGlobalMouseUp);
    return () => window.removeEventListener('mouseup', handleGlobalMouseUp);
  }, [handleMouseUp]);

  const containerClass = isDark ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-200 shadow-slate-200';

  return (
    <div 
      className={`select-none inline-block shadow-2xl p-1 rounded-sm border transition-colors duration-300 ${containerClass}`}
      onMouseLeave={handleMouseUp}
      style={{
        display: 'grid',
        gridTemplateColumns: `repeat(${grid[0].length}, 1fr)`,
        gap: '0px', 
        maxWidth: '100%',
        maxHeight: '80vh',
        aspectRatio: '1 / 1',
        width: 'min(600px, 90vw)', 
      }}
    >
      {grid.map((row, rIndex) => (
        row.map((color, cIndex) => (
          <Cell 
            key={`${rIndex}-${cIndex}`}
            rIndex={rIndex}
            cIndex={cIndex}
            color={color}
            showGridLines={showGridLines}
            boardStyle={boardStyle}
            beadSize={beadSize}
            isDark={isDark}
            onMouseDown={handleMouseDown}
            onMouseEnter={handleMouseEnter}
          />
        ))
      ))}
    </div>
  );
};

export default Grid;

// This worker handles heavy computational tasks to prevent UI blocking
// Specifically: K-Means clustering for color identification and Grid Color Mapping

// Helper: Hex to RGB
const hexToRgb = (hex: string) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    return result ? {
        r: parseInt(result[1], 16),
        g: parseInt(result[2], 16),
        b: parseInt(result[3], 16)
    } : null;
};

// Helper: RGB to Hex
const rgbToHex = (r: number, g: number, b: number): string => {
    return "#" + ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1);
};

// --- Actions ---

self.onmessage = (e: MessageEvent) => {
    const { type, payload, id } = e.data;

    try {
        let result;
        if (type === 'GET_DOMINANT_COLORS') {
            result = getDominantColors(payload.grid, payload.k);
        } else if (type === 'APPLY_PALETTE') {
            result = applyPaletteToGrid(payload.grid, payload.palette);
        }

        self.postMessage({ type, id, result, status: 'SUCCESS' });
    } catch (error: any) {
        self.postMessage({ type, id, error: error.message, status: 'ERROR' });
    }
};

// --- Algorithms ---

interface RGB { r: number; g: number; b: number; }

const getDominantColors = (grid: string[][], k: number = 5): string[] => {
    // 1. Flatten grid and extract all valid RGB values
    const pixels: RGB[] = [];
    grid.forEach(row => {
        row.forEach(color => {
            if (color !== 'transparent') {
                const rgb = hexToRgb(color);
                if (rgb) pixels.push(rgb);
            }
        });
    });

    const totalPixels = pixels.length;
    if (totalPixels === 0) return [];

    if (totalPixels <= k) {
        const unique = Array.from(new Set(pixels.map(p => rgbToHex(p.r, p.g, p.b))));
        return unique;
    }

    // 2. Initialize Centroids
    let centroids: RGB[] = [];
    const usedIndices = new Set<number>();
    while (centroids.length < k && centroids.length < totalPixels) {
        const idx = Math.floor(Math.random() * totalPixels);
        if (!usedIndices.has(idx)) {
            centroids.push({ ...pixels[idx] });
            usedIndices.add(idx);
        }
    }

    // 3. K-Means Loop
    const maxIterations = 15;
    let clusters: RGB[][] = Array.from({ length: k }, () => []);

    for (let iter = 0; iter < maxIterations; iter++) {
        clusters = Array.from({ length: k }, () => []);

        pixels.forEach(p => {
            let minDist = Infinity;
            let clusterIndex = 0;

            centroids.forEach((c, idx) => {
                const dist = (p.r - c.r) ** 2 + (p.g - c.g) ** 2 + (p.b - c.b) ** 2;
                if (dist < minDist) {
                    minDist = dist;
                    clusterIndex = idx;
                }
            });
            clusters[clusterIndex].push(p);
        });

        let converged = true;
        clusters.forEach((cluster, idx) => {
            if (cluster.length === 0) return;
            const sum = cluster.reduce((acc, p) => ({ r: acc.r + p.r, g: acc.g + p.g, b: acc.b + p.b }), { r: 0, g: 0, b: 0 });
            const newR = sum.r / cluster.length;
            const newG = sum.g / cluster.length;
            const newB = sum.b / cluster.length;

            if (Math.abs(newR - centroids[idx].r) > 1 || 
                Math.abs(newG - centroids[idx].g) > 1 || 
                Math.abs(newB - centroids[idx].b) > 1) {
                converged = false;
            }
            centroids[idx] = { r: newR, g: newG, b: newB };
        });

        if (converged) break;
    }

    const sortedClusters = clusters
        .filter(c => c.length > 0)
        .sort((a, b) => b.length - a.length);

    const threshold = Math.ceil(totalPixels * 0.01);
    const significantClusters = sortedClusters.filter(c => c.length >= threshold);

    const dominantHexColors = significantClusters.slice(0, k).map(cluster => {
        const sum = cluster.reduce((acc, p) => ({ r: acc.r + p.r, g: acc.g + p.g, b: acc.b + p.b }), { r: 0, g: 0, b: 0 });
        const avgR = Math.round(sum.r / cluster.length);
        const avgG = Math.round(sum.g / cluster.length);
        const avgB = Math.round(sum.b / cluster.length);
        return rgbToHex(avgR, avgG, avgB);
    });

    return dominantHexColors;
};

const applyPaletteToGrid = (grid: string[][], palette: string[]): string[][] => {
    if (!palette || palette.length === 0) return grid;

    const paletteRgb = palette.map(hex => {
        const rgb = hexToRgb(hex);
        return rgb ? { ...rgb, hex } : null;
    }).filter(item => item !== null) as {r: number, g: number, b: number, hex: string}[];

    if (paletteRgb.length === 0) return grid;

    const newGrid = grid.map(row => [...row]);
    const rows = newGrid.length;
    if (rows === 0) return newGrid;
    const cols = newGrid[0].length;

    for (let r = 0; r < rows; r++) {
        for (let c = 0; c < cols; c++) {
            const color = newGrid[r][c];
            if (color === 'transparent') continue;
            if (palette.includes(color)) continue;

            const currentRgb = hexToRgb(color);
            if (!currentRgb) continue;

            let minDist = Infinity;
            let nearestHex = color;

            for (const p of paletteRgb) {
                const distSq = (currentRgb.r - p.r) ** 2 + 
                               (currentRgb.g - p.g) ** 2 + 
                               (currentRgb.b - p.b) ** 2;

                if (distSq < minDist) {
                    minDist = distSq;
                    nearestHex = p.hex;
                }
            }
            newGrid[r][c] = nearestHex;
        }
    }
    return newGrid;
};

