import React, { useRef, useEffect, useCallback } from 'react';
import { GridData, ToolType, EMPTY_COLOR, BoardStyle, Language, Theme } from '../types';
import { translations } from '../utils/translations';

interface GridProps {
  grid: GridData;
  setGrid: React.Dispatch<React.SetStateAction<GridData>>;
  activeColor: string;
  setActiveColor: (c: string) => void;
  tool: ToolType;
  showGridLines: boolean;
  boardStyle: BoardStyle;
  beadSize: number;
  onStrokeEnd?: () => void;
  lang: Language;
  theme: Theme;
  isManualPicking?: boolean;
  onManualPick?: (color: string) => void;
}

// --- Cell Component (Memoized) ---
// Separating this component and using React.memo is crucial for performance on large grids (e.g. 100x100)
interface CellProps {
  rIndex: number;
  cIndex: number;
  color: string;
  showGridLines: boolean;
  boardStyle: BoardStyle;
  beadSize: number;
  isDark: boolean;
  onMouseDown: (r: number, c: number) => void;
  onMouseEnter: (r: number, c: number) => void;
  isManualPicking?: boolean;
}

const Cell = React.memo(({ 
  rIndex, 
  cIndex, 
  color, 
  showGridLines, 
  boardStyle, 
  beadSize, 
  isDark,
  onMouseDown,
  onMouseEnter,
  isManualPicking
}: CellProps) => {
  const isTransparent = color === 'transparent' || color === EMPTY_COLOR;
  const isBead = boardStyle === BoardStyle.BEAD;

  const gridLineClass = isDark ? 'border-slate-700/50' : 'border-slate-200';
  const emptyPegClass = isDark ? 'bg-slate-700 shadow-inner' : 'bg-slate-200 shadow-inner';
  const bgPatternColor = isDark ? '#1e293b' : '#e2e8f0';

  return (
    <div
      onMouseDown={() => onMouseDown(rIndex, cIndex)}
      onMouseEnter={() => onMouseEnter(rIndex, cIndex)}
      className={`
        w-full h-full flex items-center justify-center
        ${isManualPicking ? 'cursor-crosshair' : 'cursor-crosshair'}
        ${showGridLines && !isBead ? `border-[0.5px] ${gridLineClass}` : ''}
      `}
      // Prevent browser drag behavior on images/divs
      onDragStart={(e) => e.preventDefault()} 
    >
        <div 
           className={`
              transition-all duration-200 pointer-events-none
              ${isBead 
                  ? isTransparent 
                      ? `w-[20%] h-[20%] rounded-full ${emptyPegClass}` // Peg for empty bead
                      : 'rounded-full shadow-md ring-1 ring-black/10' // Filled Bead
                  : 'w-full h-full' // Square
              }
           `}
           style={{ 
              // Size logic
              width: isBead ? (isTransparent ? undefined : `${beadSize}%`) : undefined,
              height: isBead ? (isTransparent ? undefined : `${beadSize}%`) : undefined,

              backgroundColor: isBead && isTransparent ? undefined : (color === 'transparent' ? undefined : color),
              // Checkerboard pattern for transparent background
              backgroundImage: (!isBead && isTransparent)
                ? `linear-gradient(45deg, ${bgPatternColor} 25%, transparent 25%), linear-gradient(-45deg, ${bgPatternColor} 25%, transparent 25%), linear-gradient(45deg, transparent 75%, ${bgPatternColor} 75%), linear-gradient(-45deg, transparent 75%, ${bgPatternColor} 75%)` 
                : 'none',
              backgroundSize: !isBead ? '10px 10px' : undefined,
              backgroundPosition: !isBead ? '0 0, 0 5px, 5px -5px, -5px 0px' : undefined,
              // 3D effect for beads
              boxShadow: (isBead && !isTransparent) 
                ? 'inset -2px -2px 4px rgba(0,0,0,0.3), inset 2px 2px 4px rgba(255,255,255,0.25), 1px 1px 2px rgba(0,0,0,0.5)' 
                : undefined
           }}
        />
    </div>
  );
}, (prev, next) => {
  // Custom comparison to strictly limit re-renders
  return (
    prev.color === next.color &&
    prev.showGridLines === next.showGridLines &&
    prev.boardStyle === next.boardStyle &&
    prev.beadSize === next.beadSize &&
    prev.isDark === next.isDark &&
    prev.isManualPicking === next.isManualPicking
  );
});

// --- Main Grid Component ---

const Grid: React.FC<GridProps> = ({ 
  grid, 
  setGrid, 
  activeColor, 
  setActiveColor,
  tool, 
  showGridLines,
  boardStyle,
  beadSize,
  onStrokeEnd,
  lang,
  theme,
  isManualPicking = false,
  onManualPick
}) => {
  const isDrawing = useRef(false);
  const t = translations[lang];
  const isDark = theme === 'dark';

  // Refs for current state to be accessible in callbacks without re-creating functions
  const toolRef = useRef(tool);
  const activeColorRef = useRef(activeColor);
  const gridRef = useRef(grid);
  const isManualPickingRef = useRef(isManualPicking);

  useEffect(() => { toolRef.current = tool; }, [tool]);
  useEffect(() => { activeColorRef.current = activeColor; }, [activeColor]);
  useEffect(() => { gridRef.current = grid; }, [grid]);
  useEffect(() => { isManualPickingRef.current = isManualPicking; }, [isManualPicking]);

  // Safety check
  if (!grid || grid.length === 0 || !grid[0]) {
    return (
        <div className={`flex items-center justify-center w-64 h-64 ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>
            {t.loading}
        </div>
    );
  }

  // Optimized Paint Logic
  const paintCell = useCallback((rowIndex: number, colIndex: number) => {
    // Access current state via refs to avoid closure staleness without dependency updates
    // causing re-render of all cells due to function recreation
    const currentGrid = gridRef.current;
    if (rowIndex < 0 || rowIndex >= currentGrid.length || colIndex < 0 || colIndex >= currentGrid[0].length) return;

    const currentColor = currentGrid[rowIndex][colIndex];
    let targetColor = activeColorRef.current;
    const currentTool = toolRef.current;

    if (currentTool === ToolType.ERASER) {
      targetColor = EMPTY_COLOR;
    } else if (currentTool === ToolType.EYEDROPPER) {
        if (currentColor !== EMPTY_COLOR) {
            setActiveColor(currentColor);
        }
        return; 
    }

    if (currentColor === targetColor) return;

    setGrid(prev => {
      const newGrid = [...prev]; 
      newGrid[rowIndex] = [...prev[rowIndex]]; 
      newGrid[rowIndex][colIndex] = targetColor;
      return newGrid;
    });
  }, [setGrid, setActiveColor]); 

  const handleMouseDown = useCallback((r: number, c: number) => {
    // If in manual pick mode, hijack the click
    if (isManualPickingRef.current) {
        const color = gridRef.current[r][c];
        if (color !== 'transparent' && onManualPick) {
            onManualPick(color);
        }
        return;
    }

    isDrawing.current = true;
    paintCell(r, c);
  }, [paintCell, onManualPick]);

  const handleMouseEnter = useCallback((r: number, c: number) => {
    // No dragging in manual pick mode
    if (isManualPickingRef.current) return;

    if (isDrawing.current) {
      paintCell(r, c);
    }
  }, [paintCell]);

  const handleMouseUp = useCallback(() => {
    if (isDrawing.current) {
      isDrawing.current = false;
      if (onStrokeEnd) onStrokeEnd();
    }
  }, [onStrokeEnd]);

  // Global mouse up
  useEffect(() => {
    const handleGlobalMouseUp = () => { 
        if (isDrawing.current) {
            handleMouseUp();
        }
    };
    window.addEventListener('mouseup', handleGlobalMouseUp);
    return () => window.removeEventListener('mouseup', handleGlobalMouseUp);
  }, [handleMouseUp]);

  const containerClass = isDark ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-200 shadow-slate-200';

  return (
    <div 
      className={`select-none inline-block shadow-2xl p-1 rounded-sm border transition-colors duration-300 ${containerClass}`}
      onMouseLeave={handleMouseUp}
      style={{
        display: 'grid',
        gridTemplateColumns: `repeat(${grid[0].length}, 1fr)`,
        gap: '0px', 
        maxWidth: '100%',
        maxHeight: '80vh',
        aspectRatio: '1 / 1',
        width: 'min(600px, 90vw)', 
      }}
    >
      {grid.map((row, rIndex) => (
        row.map((color, cIndex) => (
          <Cell 
            key={`${rIndex}-${cIndex}`}
            rIndex={rIndex}
            cIndex={cIndex}
            color={color}
            showGridLines={showGridLines}
            boardStyle={boardStyle}
            beadSize={beadSize}
            isDark={isDark}
            onMouseDown={handleMouseDown}
            onMouseEnter={handleMouseEnter}
            isManualPicking={isManualPicking}
          />
        ))
      ))}
    </div>
  );
};

export default Grid;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Undo2, Redo2, Languages, Settings as SettingsIcon, Loader2, MousePointerClick, X, Check } from 'lucide-react';
import Grid from './components/Grid';
import Toolbar from './components/Toolbar';
import ClearConfirmationModal from './components/ClearConfirmationModal';
import SettingsModal from './components/SettingsModal';
import DominantColorsModal from './components/DominantColorsModal';
import { GridData, ToolType, DEFAULT_COLOR, EMPTY_COLOR, BoardStyle, Language, Theme, APP_CONFIG } from './types';
import { processImageToGrid, exportGridToImage } from './utils/imageHelper';
import { translations } from './utils/translations';
import { reduceGridToAverageColors } from './utils/colorUtils';

// Helper to create a fresh grid
const createGrid = (size: number): GridData => {
  return Array(size).fill(null).map(() => Array(size).fill(EMPTY_COLOR));
};

const App: React.FC = () => {
  // Language & Theme State
  const [lang, setLang] = useState<Language>('zh');
  const [theme, setTheme] = useState<Theme>('dark');

  // State
  const [gridSize, setGridSize] = useState<number>(APP_CONFIG.DEFAULT_GRID_SIZE);
  // Initialize grid immediately with the default size
  const [grid, setGrid] = useState<GridData>(() => createGrid(APP_CONFIG.DEFAULT_GRID_SIZE));
  const [activeColor, setActiveColor] = useState<string>(DEFAULT_COLOR);
  const [tool, setTool] = useState<ToolType>(ToolType.PEN);
  const [showGridLines, setShowGridLines] = useState<boolean>(true);
  const [boardStyle, setBoardStyle] = useState<BoardStyle>(BoardStyle.SQUARE);
  const [beadSize, setBeadSize] = useState<number>(APP_CONFIG.DEFAULT_BEAD_SIZE); // Percentage 20-100

  // History State
  const [history, setHistory] = useState<GridData[]>([]);
  const [historyIndex, setHistoryIndex] = useState<number>(-1);

  // Modal States
  const [isClearModalOpen, setIsClearModalOpen] = useState(false);
  const [skipClearConfirm, setSkipClearConfirm] = useState(false);
  const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);

  // Dominant Colors Modal State
  const [isColorModalOpen, setIsColorModalOpen] = useState(false);
  const [dominantColors, setDominantColors] = useState<string[]>([]);

  // Manual Extraction State
  const [isManualPicking, setIsManualPicking] = useState(false);
  const [manualPalette, setManualPalette] = useState<string[]>([]);

  // Worker State
  const workerRef = useRef<Worker | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  // Get current translations
  const t = translations[lang];
  const isDark = theme === 'dark';

  // Initialize Worker
  useEffect(() => {
    let worker: Worker;

    // Attempt to initialize worker with safe fallback for environments where import.meta.url might be missing
    try {
        const workerUrl = new URL('./utils/pixelWorker.ts', import.meta.url);
        worker = new Worker(workerUrl, { type: 'module' });
    } catch (e) {
        // Fallback: Use absolute path relative to root
        worker = new Worker('/utils/pixelWorker.ts', { type: 'module' });
    }

    workerRef.current = worker;

    return () => {
        worker.terminate();
    };
  }, []);

  // Initialize history on first load or reset
  useEffect(() => {
    const initialGrid = createGrid(gridSize);
    setGrid(initialGrid);
    setHistory([initialGrid]);
    setHistoryIndex(0);
  }, [gridSize]); // Reset everything when grid size changes

  // History Helper: Add current grid state to history
  const addToHistory = useCallback((newGridState: GridData) => {
    setHistory(prev => {
      const newHistory = prev.slice(0, historyIndex + 1);
      // Deep copy to ensure history immutability
      const copy = JSON.parse(JSON.stringify(newGridState));
      newHistory.push(copy);
      return newHistory;
    });
    setHistoryIndex(prev => prev + 1);
  }, [historyIndex]);

  // Handle Undo
  const handleUndo = () => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      setHistoryIndex(newIndex);
      setGrid(JSON.parse(JSON.stringify(history[newIndex])));
    }
  };

  // Handle Redo
  const handleRedo = () => {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      setHistoryIndex(newIndex);
      setGrid(JSON.parse(JSON.stringify(history[newIndex])));
    }
  };

  // Handlers
  const handleStrokeEnd = () => {
    addToHistory(grid);
  };

  // Logic to actually perform the clear operation
  const performClear = () => {
    const newGrid = createGrid(gridSize);
    setGrid(newGrid);
    addToHistory(newGrid);
    setIsClearModalOpen(false);
  };

  // Triggered when user clicks "Clear" in toolbar
  const handleClearRequest = () => {
    if (skipClearConfirm) {
        performClear();
    } else {
        setIsClearModalOpen(true);
    }
  };

  // Triggered when user confirms in the modal
  const handleConfirmClear = (dontShowAgain: boolean) => {
    if (dontShowAgain) {
        setSkipClearConfirm(true);
    }
    performClear();
  };

  const handleDownload = () => {
    exportGridToImage(grid, boardStyle, beadSize);
  };

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    try {
      const newGrid = await processImageToGrid(file, gridSize, gridSize);
      setGrid(newGrid);
      addToHistory(newGrid);
      // Reset file input
      e.target.value = '';
    } catch (error) {
      console.error("Failed to process image", error);
      alert(t.error_processing_alert);
    } finally {
      setIsProcessing(false);
    }
  };

  // Helper to communicate with worker
  const runWorkerTask = (type: string, payload: any): Promise<any> => {
    return new Promise((resolve, reject) => {
        if (!workerRef.current) {
            reject("Worker not initialized");
            return;
        }

        const id = Math.random().toString(36).substr(2, 9);

        const handleMessage = (e: MessageEvent) => {
            if (e.data.id === id) {
                workerRef.current?.removeEventListener('message', handleMessage);
                if (e.data.status === 'SUCCESS') {
                    resolve(e.data.result);
                } else {
                    reject(e.data.error);
                }
            }
        };

        workerRef.current.onerror = (err) => {
            reject(err);
        };

        workerRef.current.addEventListener('message', handleMessage);
        workerRef.current.postMessage({ type, payload, id });
    });
  };

  const handleIdentifyColors = async () => {
    setIsProcessing(true);
    try {
        const colors = await runWorkerTask('GET_DOMINANT_COLORS', { grid, k: 10 });
        setDominantColors(colors);
        setIsColorModalOpen(true);
    } catch (e) {
        console.error(e);
        alert("Computation Error or Worker failed to load.");
    } finally {
        setIsProcessing(false);
    }
  };

  const handleApplyPalette = async (selectedColors: string[]) => {
    setIsProcessing(true);
    setIsColorModalOpen(false); // Close modal immediately
    try {
        const newGrid = await runWorkerTask('APPLY_PALETTE', { grid, palette: selectedColors });
        setGrid(newGrid);
        addToHistory(newGrid);
    } catch (e) {
        console.error(e);
        alert("Computation Error");
    } finally {
        setIsProcessing(false);
    }
  };

  const toggleLanguage = () => {
    setLang(prev => prev === 'zh' ? 'en' : 'zh');
  };

  // --- Manual Extraction Logic ---

  const handleStartManualExtract = () => {
    setIsManualPicking(true);
    setManualPalette([]);
  };

  const handleCancelManualExtract = () => {
    setIsManualPicking(false);
    setManualPalette([]);
  };

  const handleManualColorPick = (color: string) => {
    if (manualPalette.length >= 10) return;
    if (manualPalette.includes(color)) return;
    setManualPalette(prev => [...prev, color]);
  };

  const handleRemoveManualColor = (colorToRemove: string) => {
    setManualPalette(prev => prev.filter(c => c !== colorToRemove));
  };

  const handleConfirmManualExtract = async () => {
    if (manualPalette.length === 0) return;

    setIsProcessing(true);
    setIsManualPicking(false);
    try {
        const newGrid = await runWorkerTask('APPLY_PALETTE', { grid, palette: manualPalette });
        setGrid(newGrid);
        addToHistory(newGrid);
    } catch (e) {
        console.error(e);
        alert("Computation Error");
    } finally {
        setIsProcessing(false);
    }
  };

  return (
    <div className={`min-h-screen flex flex-col items-center justify-center p-4 md:p-8 relative overflow-hidden transition-colors duration-500 ${isDark ? 'bg-slate-900 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>

      {/* Background decoration */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0">
         <div className={`absolute top-[-20%] left-[-10%] w-[50%] h-[50%] rounded-full blur-[120px] transition-colors duration-500 ${isDark ? 'bg-blue-600/10' : 'bg-blue-400/20'}`}></div>
         <div className={`absolute bottom-[-20%] right-[-10%] w-[50%] h-[50%] rounded-full blur-[120px] transition-colors duration-500 ${isDark ? 'bg-purple-600/10' : 'bg-purple-400/20'}`}></div>
      </div>

      <header className="mb-8 z-10 text-center relative w-full max-w-6xl">
        {/* Desktop Controls */}
        <div className="absolute right-0 top-0 hidden md:flex items-center gap-2">
            <button 
                onClick={toggleLanguage}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full border transition-colors text-xs font-medium ${isDark ? 'bg-slate-800 border-slate-700 hover:bg-slate-700 text-slate-300' : 'bg-white border-slate-200 hover:bg-slate-50 text-slate-600'}`}
            >
                <Languages size={14} />
                {lang === 'zh' ? 'EN' : '中文'}
            </button>
            <button 
                onClick={() => setIsSettingsModalOpen(true)}
                className={`p-1.5 rounded-full border transition-colors ${isDark ? 'bg-slate-800 border-slate-700 hover:bg-slate-700 text-slate-300' : 'bg-white border-slate-200 hover:bg-slate-50 text-slate-600'}`}
            >
                <SettingsIcon size={14} />
            </button>
        </div>

        {/* Mobile Controls */}
        <div className="absolute right-0 top-[-10px] md:hidden flex gap-2">
            <button 
                onClick={toggleLanguage}
                className={`p-2 rounded-full border transition-colors ${isDark ? 'bg-slate-800 border-slate-700 hover:bg-slate-700 text-slate-300' : 'bg-white border-slate-200 hover:bg-slate-50 text-slate-600'}`}
            >
                <Languages size={16} />
            </button>
             <button 
                onClick={() => setIsSettingsModalOpen(true)}
                className={`p-2 rounded-full border transition-colors ${isDark ? 'bg-slate-800 border-slate-700 hover:bg-slate-700 text-slate-300' : 'bg-white border-slate-200 hover:bg-slate-50 text-slate-600'}`}
            >
                <SettingsIcon size={16} />
            </button>
        </div>

        <h1 className="text-4xl md:text-5xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-purple-400 mb-2">
          {t.title}
        </h1>
        <p className={isDark ? "text-slate-400" : "text-slate-500"}>{t.subtitle}</p>
      </header>

      <main className="w-full max-w-6xl z-10 flex flex-col md:flex-row gap-8 items-start justify-center relative">

        {/* Loading Overlay */}
        {isProcessing && (
            <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-black/50 backdrop-blur-sm rounded-3xl">
                <Loader2 className="w-12 h-12 text-blue-400 animate-spin mb-4" />
                <p className="text-white font-medium">{t.loading}...</p>
            </div>
        )}

        {/* Left Control Panel (Mobile: Top) */}
        <section className="w-full md:w-auto order-2 md:order-1 flex justify-center">
          <Toolbar 
            tool={tool}
            setTool={setTool}
            activeColor={activeColor}
            setActiveColor={setActiveColor}
            gridSize={gridSize}
            setGridSize={setGridSize}
            onClear={handleClearRequest}
            onDownload={handleDownload}
            onUpload={handleUpload}
            onIdentifyColors={handleIdentifyColors}
            onManualExtract={handleStartManualExtract}
            showGridLines={showGridLines}
            setShowGridLines={setShowGridLines}
            boardStyle={boardStyle}
            setBoardStyle={setBoardStyle}
            beadSize={beadSize}
            setBeadSize={setBeadSize}
            lang={lang}
            theme={theme}
          />
        </section>

        {/* Center Canvas */}
        <section className={`flex-1 order-1 md:order-2 p-4 md:p-8 rounded-3xl border shadow-2xl backdrop-blur-sm flex flex-col items-center transition-colors duration-300 relative ${isDark ? 'bg-slate-800/30 border-slate-700/50' : 'bg-white/60 border-slate-200'}`}>

           {/* Canvas Header (Undo/Redo) */}
           <div className="w-full flex justify-end gap-2 mb-4">
              <button 
                type="button"
                onClick={handleUndo}
                disabled={historyIndex <= 0}
                className={`p-2 rounded-lg transition-colors disabled:opacity-30 ${isDark ? 'bg-slate-700 hover:bg-slate-600 text-slate-200 disabled:hover:bg-slate-700' : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 disabled:hover:bg-white'}`}
                title={t.undo}
              >
                <Undo2 size={20} />
              </button>
              <button 
                type="button"
                onClick={handleRedo}
                disabled={historyIndex >= history.length - 1}
                className={`p-2 rounded-lg transition-colors disabled:opacity-30 ${isDark ? 'bg-slate-700 hover:bg-slate-600 text-slate-200 disabled:hover:bg-slate-700' : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 disabled:hover:bg-white'}`}
                title={t.redo}
              >
                <Redo2 size={20} />
              </button>
           </div>

           <Grid 
             grid={grid}
             setGrid={setGrid}
             activeColor={activeColor}
             setActiveColor={setActiveColor}
             tool={tool}
             showGridLines={showGridLines}
             boardStyle={boardStyle}
             beadSize={beadSize}
             onStrokeEnd={handleStrokeEnd}
             lang={lang}
             theme={theme}
             isManualPicking={isManualPicking}
             onManualPick={handleManualColorPick}
           />

           {/* Manual Selection Overlay */}
           {isManualPicking && (
              <div className={`absolute bottom-6 left-1/2 -translate-x-1/2 p-4 rounded-xl shadow-2xl border animate-in slide-in-from-bottom-5 w-[90%] max-w-md backdrop-blur-md z-20 ${isDark ? 'bg-slate-900/90 border-slate-700' : 'bg-white/90 border-slate-200'}`}>
                 <div className="flex justify-between items-start mb-3">
                    <div>
                        <h4 className={`text-sm font-bold flex items-center gap-2 ${isDark ? 'text-white' : 'text-slate-900'}`}>
                            <MousePointerClick size={16} className="text-blue-500"/>
                            {t.manual_pick_title}
                        </h4>
                        <p className={`text-xs ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>{t.manual_pick_desc}</p>
                    </div>
                    <span className={`text-xs font-mono font-bold px-2 py-1 rounded ${isDark ? 'bg-slate-800 text-blue-400' : 'bg-slate-100 text-blue-600'}`}>
                        {manualPalette.length}/10
                    </span>
                 </div>

                 {/* Selected Colors Strip */}
                 <div className="flex gap-2 mb-4 overflow-x-auto py-1 min-h-[40px]">
                    {manualPalette.length === 0 ? (
                        <div className={`w-full text-center text-xs italic py-2 ${isDark ? 'text-slate-600' : 'text-slate-400'}`}>
                            {t.select_colors_instruction}
                        </div>
                    ) : (
                        manualPalette.map((c, i) => (
                            <button
                                key={i}
                                onClick={() => handleRemoveManualColor(c)}
                                className="w-8 h-8 rounded-full shadow-sm ring-1 ring-black/10 flex-shrink-0 group relative overflow-hidden transition-transform hover:scale-105"
                                style={{ backgroundColor: c }}
                            >
                                <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                    <X size={14} className="text-white"/>
                                </div>
                            </button>
                        ))
                    )}
                 </div>

                 {/* Actions */}
                 <div className="flex gap-2">
                    <button 
                        onClick={handleCancelManualExtract}
                        className={`flex-1 py-2 rounded-lg text-xs font-medium transition-colors ${isDark ? 'bg-slate-800 hover:bg-slate-700 text-slate-300' : 'bg-slate-100 hover:bg-slate-200 text-slate-600'}`}
                    >
                        {t.cancel}
                    </button>
                    <button 
                        onClick={handleConfirmManualExtract}
                        disabled={manualPalette.length === 0}
                        className={`flex-1 py-2 rounded-lg text-xs font-bold text-white transition-all shadow-lg flex items-center justify-center gap-2 ${manualPalette.length > 0 ? 'bg-blue-600 hover:bg-blue-500 shadow-blue-500/20' : 'bg-slate-600 opacity-50 cursor-not-allowed'}`}
                    >
                        {t.manual_pick_confirm}
                        <Check size={14} />
                    </button>
                 </div>
              </div>
           )}

        </section>

      </main>

      <footer className={`mt-12 text-sm z-10 ${isDark ? 'text-slate-600' : 'text-slate-400'}`}>
        <p>{t.footer_text}</p>
      </footer>

      {/* Modals */}
      <ClearConfirmationModal 
        isOpen={isClearModalOpen}
        onClose={() => setIsClearModalOpen(false)}
        onConfirm={handleConfirmClear}
        lang={lang}
        theme={theme}
      />

      <SettingsModal 
        isOpen={isSettingsModalOpen}
        onClose={() => setIsSettingsModalOpen(false)}
        theme={theme}
        setTheme={setTheme}
        lang={lang}
      />

      <DominantColorsModal
        isOpen={isColorModalOpen}
        onClose={() => setIsColorModalOpen(false)}
        colors={dominantColors}
        lang={lang}
        theme={theme}
        onApply={handleApplyPalette}
      />
    </div>
  );
};

export default App;

