// Converts RGB to Hex
export const rgbToHex = (r: number, g: number, b: number): string => {
  return "#" + ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1);
};

// Converts Hex to RGB
export const hexToRgb = (hex: string) => {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16)
  } : null;
};

// Converts RGB to HSV
// H: 0-360, S: 0-1, V: 0-1
const rgbToHsv = (r: number, g: number, b: number) => {
    r /= 255; g /= 255; b /= 255;
    const max = Math.max(r, g, b);
    const min = Math.min(r, g, b);
    let h = 0, s = 0, v = max;
    const d = max - min;
    s = max === 0 ? 0 : d / max;
    if (max !== min) {
        switch (max) {
            case r: h = (g - b) / d + (g < b ? 6 : 0); break;
            case g: h = (b - r) / d + 2; break;
            case b: h = (r - g) / d + 4; break;
        }
        h /= 6;
    }
    return { h: h * 360, s, v };
};

/**
 * Calculates the weighted distance between two colors based on the user-specified formula.
 * Formula: Similarity = 1 - (0.6*H_dist + 0.2*SV_dist + 0.2*RGB_dist)
 * We return the weighted Distance (the part in parentheses), so smaller is better.
 */
const calculateHybridDistance = (r1: number, g1: number, b1: number, r2: number, g2: number, b2: number): number => {
    // 1. RGB Distance (Euclidean, Normalized to 0-1)
    const dr = r1 - r2;
    const dg = g1 - g2;
    const db = b1 - b2;
    // Max euclidean distance in RGB is sqrt(255^2 * 3) ≈ 441.67
    const distRGB = Math.sqrt(dr*dr + dg*dg + db*db) / 441.67; 

    // 2. HSV Calculations
    const hsv1 = rgbToHsv(r1, g1, b1);
    const hsv2 = rgbToHsv(r2, g2, b2);

    // 3. Hue Distance (Circular, Normalized to 0-1)
    let dh = Math.abs(hsv1.h - hsv2.h);
    if (dh > 180) dh = 360 - dh; // Shortest path around the circle
    const distH = dh / 180;

    // 4. S/V Distance (Euclidean in SV plane, Normalized to 0-1)
    // Max distance in unit square (0-1, 0-1) is sqrt(1^2 + 1^2) = sqrt(2) ≈ 1.414
    const ds = hsv1.s - hsv2.s;
    const dv = hsv1.v - hsv2.v;
    const distSV = Math.sqrt(ds*ds + dv*dv) / 1.414;

    // 5. Weighted Sum
    // 0.6 * H distance + 0.2 * SV distance + 0.2 * RGB distance
    return (0.6 * distH) + (0.2 * distSV) + (0.2 * distRGB);
};

interface RGB { r: number; g: number; b: number; }

// Reference point structure derived from CSV
interface ColorReference {
  r: number;
  g: number;
  b: number;
  labelId: string;
}

// Parse CSV content into usable reference points
const parseReferencePoints = (csv: string): ColorReference[] => {
  const lines = csv.trim().split('\n');
  const refs: ColorReference[] = [];
  // Determine start index based on header presence
  const startIndex = lines[0].startsWith('R,G,B') ? 1 : 0;

  for (let i = startIndex; i < lines.length; i++) {
    const parts = lines[i].split(',');
    if (parts.length < 6) continue;

    const r = parseInt(parts[0], 10);
    const g = parseInt(parts[1], 10);
    const b = parseInt(parts[2], 10);
    // Label ID is at index 5
    const labelId = parts[5].trim();

    if (!isNaN(r)) {
        refs.push({ r, g, b, labelId });
    }
  }
  return refs;
};

// Load reference points into memory immediately
const REFERENCE_POINTS = parseReferencePoints(COLOR_CSV_DATA);

/**
 * Reduces the grid colors by matching each pixel to the nearest neighbor
 * found in the provided CSV dataset (categorization).
 * Uses the Hybrid HSV+RGB distance metric.
 */
export const reduceGridToAverageColors = (grid: string[][]): string[][] => {
  const newGrid = grid.map(row => [...row]);
  const rows = newGrid.length;
  if (rows === 0) return newGrid;
  const cols = newGrid[0].length;

  const groups: Record<string, { r: number, g: number, b: number, row: number, col: number }[]> = {};

  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const color = newGrid[r][c];
      if (color === 'transparent') continue;

      const rgb = hexToRgb(color);
      if (!rgb) continue;

      const { r: R, g: G, b: B } = rgb;

      let minDist = Infinity;
      let bestLabel = 'unknown';

      // Find nearest neighbor in CSV reference points
      for (const ref of REFERENCE_POINTS) {
        // Use Hybrid Distance
        const dist = calculateHybridDistance(R, G, B, ref.r, ref.g, ref.b);

        if (dist < minDist) {
          minDist = dist;
          bestLabel = ref.labelId;
        }
      }

      if (!groups[bestLabel]) {
        groups[bestLabel] = [];
      }
      groups[bestLabel].push({ r: R, g: G, b: B, row: r, col: c });
    }
  }

  // Calculate average for each group and apply to grid
  Object.keys(groups).forEach(label => {
      const pixels = groups[label];
      if (pixels.length === 0) return;

      const total = pixels.reduce((acc, p) => ({ 
          r: acc.r + p.r, 
          g: acc.g + p.g, 
          b: acc.b + p.b 
      }), { r: 0, g: 0, b: 0 });

      const avgR = Math.round(total.r / pixels.length);
      const avgG = Math.round(total.g / pixels.length);
      const avgB = Math.round(total.b / pixels.length);

      const avgHex = rgbToHex(avgR, avgG, avgB);

      pixels.forEach(p => {
          newGrid[p.row][p.col] = avgHex;
      });
  });

  return newGrid;
};

/**
 * Identifies the top K dominant average colors using K-Means clustering.
 * Uses Hybrid HSV+RGB distance metric for assignment.
 */
export const getDominantColors = (grid: string[][], k: number = 5): string[] => {
  // 1. Flatten grid and extract all valid RGB values
  const pixels: RGB[] = [];
  grid.forEach(row => {
    row.forEach(color => {
      if (color !== 'transparent') {
        const rgb = hexToRgb(color);
        if (rgb) pixels.push(rgb);
      }
    });
  });

  const totalPixels = pixels.length;
  if (totalPixels === 0) return [];

  if (totalPixels <= k) {
      const unique = Array.from(new Set(pixels.map(p => rgbToHex(p.r, p.g, p.b))));
      return unique;
  }

  // 2. Initialize Centroids (Pick random pixels to start)
  let centroids: RGB[] = [];
  const usedIndices = new Set<number>();
  while (centroids.length < k && centroids.length < totalPixels) {
      const idx = Math.floor(Math.random() * totalPixels);
      if (!usedIndices.has(idx)) {
          centroids.push({ ...pixels[idx] });
          usedIndices.add(idx);
      }
  }

  // 3. K-Means Loop
  const maxIterations = 15;
  let clusters: RGB[][] = Array.from({ length: k }, () => []);

  for (let iter = 0; iter < maxIterations; iter++) {
      clusters = Array.from({ length: k }, () => []);

      // Assign pixels to nearest centroid using Hybrid Distance
      pixels.forEach(p => {
          let minDist = Infinity;
          let clusterIndex = 0;

          centroids.forEach((c, idx) => {
              const dist = calculateHybridDistance(p.r, p.g, p.b, c.r, c.g, c.b);
              if (dist < minDist) {
                  minDist = dist;
                  clusterIndex = idx;
              }
          });
          clusters[clusterIndex].push(p);
      });

      // Recalculate centroids (Arithmetic Mean in RGB space is still a robust estimator)
      let converged = true;
      clusters.forEach((cluster, idx) => {
          if (cluster.length === 0) return;

          const sum = cluster.reduce((acc, p) => ({ r: acc.r + p.r, g: acc.g + p.g, b: acc.b + p.b }), { r: 0, g: 0, b: 0 });
          const newR = sum.r / cluster.length;
          const newG = sum.g / cluster.length;
          const newB = sum.b / cluster.length;

          // Convergence check
          if (Math.abs(newR - centroids[idx].r) > 1 || 
              Math.abs(newG - centroids[idx].g) > 1 || 
              Math.abs(newB - centroids[idx].b) > 1) {
              converged = false;
          }

          centroids[idx] = { r: newR, g: newG, b: newB };
      });

      if (converged) break;
  }

  // 4. Sort clusters by size
  const sortedClusters = clusters
      .filter(c => c.length > 0)
      .sort((a, b) => b.length - a.length);

  // 5. Filter thresholds: > 0.5% total and > 5 pixels
  const threshold = Math.ceil(totalPixels * 0.005);
  const significantClusters = sortedClusters.filter(c => c.length >= threshold && c.length > 5);

  const dominantHexColors = significantClusters.slice(0, k).map(cluster => {
      const sum = cluster.reduce((acc, p) => ({ r: acc.r + p.r, g: acc.g + p.g, b: acc.b + p.b }), { r: 0, g: 0, b: 0 });
      const avgR = Math.round(sum.r / cluster.length);
      const avgG = Math.round(sum.g / cluster.length);
      const avgB = Math.round(sum.b / cluster.length);
      return rgbToHex(avgR, avgG, avgB);
  });

  return dominantHexColors;
};

/**
 * Replaces every pixel in the grid with the nearest color from the provided palette.
 * Uses Hybrid HSV+RGB distance metric.
 */
export const applyPaletteToGrid = (grid: string[][], palette: string[]): string[][] => {
  if (!palette || palette.length === 0) return grid;

  const paletteRgb = palette.map(hex => {
      const rgb = hexToRgb(hex);
      return rgb ? { ...rgb, hex } : null;
  }).filter(item => item !== null) as {r: number, g: number, b: number, hex: string}[];

  if (paletteRgb.length === 0) return grid;

  const newGrid = grid.map(row => [...row]);
  const rows = newGrid.length;
  if (rows === 0) return newGrid;
  const cols = newGrid[0].length;

  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const color = newGrid[r][c];
      if (color === 'transparent') continue;

      if (palette.includes(color)) continue;

      const currentRgb = hexToRgb(color);
      if (!currentRgb) continue;

      let minDist = Infinity;
      let nearestHex = color;

      for (const p of paletteRgb) {
        // Use Hybrid Distance
        const dist = calculateHybridDistance(currentRgb.r, currentRgb.g, currentRgb.b, p.r, p.g, p.b);

        if (dist < minDist) {
          minDist = dist;
          nearestHex = p.hex;
        }
      }
      newGrid[r][c] = nearestHex;
    }
  }

  return newGrid;
};

import React, { useState, useEffect, useCallback } from 'react';
import { Undo2, Redo2, Languages, Settings as SettingsIcon } from 'lucide-react';
import Grid from './components/Grid';
import Toolbar from './components/Toolbar';
import ClearConfirmationModal from './components/ClearConfirmationModal';
import SettingsModal from './components/SettingsModal';
import DominantColorsModal from './components/DominantColorsModal';
import { GridData, ToolType, DEFAULT_COLOR, EMPTY_COLOR, BoardStyle, Language, Theme, APP_CONFIG } from './types';
import { processImageToGrid, exportGridToImage } from './utils/imageHelper';
import { translations } from './utils/translations';
import { reduceGridToAverageColors, getDominantColors, applyPaletteToGrid } from './utils/colorUtils';

// Helper to create a fresh grid
const createGrid = (size: number): GridData => {
  return Array(size).fill(null).map(() => Array(size).fill(EMPTY_COLOR));
};

const App: React.FC = () => {
  // Language & Theme State
  const [lang, setLang] = useState<Language>('zh');
  const [theme, setTheme] = useState<Theme>('dark');

  // State
  const [gridSize, setGridSize] = useState<number>(APP_CONFIG.DEFAULT_GRID_SIZE);
  // Initialize grid immediately with the default size
  const [grid, setGrid] = useState<GridData>(() => createGrid(APP_CONFIG.DEFAULT_GRID_SIZE));
  const [activeColor, setActiveColor] = useState<string>(DEFAULT_COLOR);
  const [tool, setTool] = useState<ToolType>(ToolType.PEN);
  const [showGridLines, setShowGridLines] = useState<boolean>(true);
  const [boardStyle, setBoardStyle] = useState<BoardStyle>(BoardStyle.SQUARE);
  const [beadSize, setBeadSize] = useState<number>(APP_CONFIG.DEFAULT_BEAD_SIZE); // Percentage 20-100

  // History State
  const [history, setHistory] = useState<GridData[]>([]);
  const [historyIndex, setHistoryIndex] = useState<number>(-1);

  // Modal States
  const [isClearModalOpen, setIsClearModalOpen] = useState(false);
  const [skipClearConfirm, setSkipClearConfirm] = useState(false);
  const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);

  // Dominant Colors Modal State
  const [isColorModalOpen, setIsColorModalOpen] = useState(false);
  const [dominantColors, setDominantColors] = useState<string[]>([]);

  // Get current translations
  const t = translations[lang];
  const isDark = theme === 'dark';

  // Initialize history on first load or reset
  useEffect(() => {
    const initialGrid = createGrid(gridSize);
    setGrid(initialGrid);
    setHistory([initialGrid]);
    setHistoryIndex(0);
  }, [gridSize]); // Reset everything when grid size changes

  // History Helper: Add current grid state to history
  const addToHistory = useCallback((newGridState: GridData) => {
    setHistory(prev => {
      const newHistory = prev.slice(0, historyIndex + 1);
      // Deep copy to ensure history immutability
      const copy = JSON.parse(JSON.stringify(newGridState));
      newHistory.push(copy);
      return newHistory;
    });
    setHistoryIndex(prev => prev + 1);
  }, [historyIndex]);

  // Handle Undo
  const handleUndo = () => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      setHistoryIndex(newIndex);
      setGrid(JSON.parse(JSON.stringify(history[newIndex])));
    }
  };

  // Handle Redo
  const handleRedo = () => {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      setHistoryIndex(newIndex);
      setGrid(JSON.parse(JSON.stringify(history[newIndex])));
    }
  };

  // Handlers
  const handleStrokeEnd = () => {
    addToHistory(grid);
  };

  // Logic to actually perform the clear operation
  const performClear = () => {
    const newGrid = createGrid(gridSize);
    setGrid(newGrid);
    addToHistory(newGrid);
    setIsClearModalOpen(false);
  };

  // Triggered when user clicks "Clear" in toolbar
  const handleClearRequest = () => {
    if (skipClearConfirm) {
        performClear();
    } else {
        setIsClearModalOpen(true);
    }
  };

  // Triggered when user confirms in the modal
  const handleConfirmClear = (dontShowAgain: boolean) => {
    if (dontShowAgain) {
        setSkipClearConfirm(true);
    }
    performClear();
  };

  const handleDownload = () => {
    exportGridToImage(grid);
  };

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const newGrid = await processImageToGrid(file, gridSize, gridSize);
      setGrid(newGrid);
      addToHistory(newGrid);
      // Reset file input
      e.target.value = '';
    } catch (error) {
      console.error("Failed to process image", error);
      alert(t.error_processing_alert);
    }
  };

  const handleIdentifyColors = () => {
    const colors = getDominantColors(grid, 10);
    setDominantColors(colors);
    setIsColorModalOpen(true);
  };

  const handleApplyPalette = (selectedColors: string[]) => {
    const newGrid = applyPaletteToGrid(grid, selectedColors);
    setGrid(newGrid);
    addToHistory(newGrid);
    setIsColorModalOpen(false);
  };

  const toggleLanguage = () => {
    setLang(prev => prev === 'zh' ? 'en' : 'zh');
  };

  return (
    <div className={`min-h-screen flex flex-col items-center justify-center p-4 md:p-8 relative overflow-hidden transition-colors duration-500 ${isDark ? 'bg-slate-900 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>

      {/* Background decoration */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0">
         <div className={`absolute top-[-20%] left-[-10%] w-[50%] h-[50%] rounded-full blur-[120px] transition-colors duration-500 ${isDark ? 'bg-blue-600/10' : 'bg-blue-400/20'}`}></div>
         <div className={`absolute bottom-[-20%] right-[-10%] w-[50%] h-[50%] rounded-full blur-[120px] transition-colors duration-500 ${isDark ? 'bg-purple-600/10' : 'bg-purple-400/20'}`}></div>
      </div>

      <header className="mb-8 z-10 text-center relative w-full max-w-6xl">
        {/* Desktop Controls */}
        <div className="absolute right-0 top-0 hidden md:flex items-center gap-2">
            <button 
                onClick={toggleLanguage}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full border transition-colors text-xs font-medium ${isDark ? 'bg-slate-800 border-slate-700 hover:bg-slate-700 text-slate-300' : 'bg-white border-slate-200 hover:bg-slate-50 text-slate-600'}`}
            >
                <Languages size={14} />
                {lang === 'zh' ? 'EN' : '中文'}
            </button>
            <button 
                onClick={() => setIsSettingsModalOpen(true)}
                className={`p-1.5 rounded-full border transition-colors ${isDark ? 'bg-slate-800 border-slate-700 hover:bg-slate-700 text-slate-300' : 'bg-white border-slate-200 hover:bg-slate-50 text-slate-600'}`}
            >
                <SettingsIcon size={14} />
            </button>
        </div>

        {/* Mobile Controls */}
        <div className="absolute right-0 top-[-10px] md:hidden flex gap-2">
            <button 
                onClick={toggleLanguage}
                className={`p-2 rounded-full border transition-colors ${isDark ? 'bg-slate-800 border-slate-700 hover:bg-slate-700 text-slate-300' : 'bg-white border-slate-200 hover:bg-slate-50 text-slate-600'}`}
            >
                <Languages size={16} />
            </button>
             <button 
                onClick={() => setIsSettingsModalOpen(true)}
                className={`p-2 rounded-full border transition-colors ${isDark ? 'bg-slate-800 border-slate-700 hover:bg-slate-700 text-slate-300' : 'bg-white border-slate-200 hover:bg-slate-50 text-slate-600'}`}
            >
                <SettingsIcon size={16} />
            </button>
        </div>

        <h1 className="text-4xl md:text-5xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-purple-400 mb-2">
          {t.title}
        </h1>
        <p className={isDark ? "text-slate-400" : "text-slate-500"}>{t.subtitle}</p>
      </header>

      <main className="w-full max-w-6xl z-10 flex flex-col md:flex-row gap-8 items-start justify-center">

        {/* Left Control Panel (Mobile: Top) */}
        <section className="w-full md:w-auto order-2 md:order-1 flex justify-center">
          <Toolbar 
            tool={tool}
            setTool={setTool}
            activeColor={activeColor}
            setActiveColor={setActiveColor}
            gridSize={gridSize}
            setGridSize={setGridSize}
            onClear={handleClearRequest}
            onDownload={handleDownload}
            onUpload={handleUpload}
            onIdentifyColors={handleIdentifyColors}
            showGridLines={showGridLines}
            setShowGridLines={setShowGridLines}
            boardStyle={boardStyle}
            setBoardStyle={setBoardStyle}
            beadSize={beadSize}
            setBeadSize={setBeadSize}
            lang={lang}
            theme={theme}
          />
        </section>

        {/* Center Canvas */}
        <section className={`flex-1 order-1 md:order-2 p-4 md:p-8 rounded-3xl border shadow-2xl backdrop-blur-sm flex flex-col items-center transition-colors duration-300 ${isDark ? 'bg-slate-800/30 border-slate-700/50' : 'bg-white/60 border-slate-200'}`}>

           {/* Canvas Header (Undo/Redo) */}
           <div className="w-full flex justify-end gap-2 mb-4">
              <button 
                type="button"
                onClick={handleUndo}
                disabled={historyIndex <= 0}
                className={`p-2 rounded-lg transition-colors disabled:opacity-30 ${isDark ? 'bg-slate-700 hover:bg-slate-600 text-slate-200 disabled:hover:bg-slate-700' : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 disabled:hover:bg-white'}`}
                title={t.undo}
              >
                <Undo2 size={20} />
              </button>
              <button 
                type="button"
                onClick={handleRedo}
                disabled={historyIndex >= history.length - 1}
                className={`p-2 rounded-lg transition-colors disabled:opacity-30 ${isDark ? 'bg-slate-700 hover:bg-slate-600 text-slate-200 disabled:hover:bg-slate-700' : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 disabled:hover:bg-white'}`}
                title={t.redo}
              >
                <Redo2 size={20} />
              </button>
           </div>

           <Grid 
             grid={grid}
             setGrid={setGrid}
             activeColor={activeColor}
             setActiveColor={setActiveColor}
             tool={tool}
             showGridLines={showGridLines}
             boardStyle={boardStyle}
             beadSize={beadSize}
             onStrokeEnd={handleStrokeEnd}
             lang={lang}
             theme={theme}
           />
        </section>

      </main>

      <footer className={`mt-12 text-sm z-10 ${isDark ? 'text-slate-600' : 'text-slate-400'}`}>
        <p>{t.footer_text}</p>
      </footer>

      {/* Modals */}
      <ClearConfirmationModal 
        isOpen={isClearModalOpen}
        onClose={() => setIsClearModalOpen(false)}
        onConfirm={handleConfirmClear}
        lang={lang}
        theme={theme}
      />

      <SettingsModal 
        isOpen={isSettingsModalOpen}
        onClose={() => setIsSettingsModalOpen(false)}
        theme={theme}
        setTheme={setTheme}
        lang={lang}
      />

      <DominantColorsModal
        isOpen={isColorModalOpen}
        onClose={() => setIsColorModalOpen(false)}
        colors={dominantColors}
        lang={lang}
        theme={theme}
        onApply={handleApplyPalette}
      />
    </div>
  );
};

export default App;
